export const QB: Question[] = [
  // SCENARIO 1
  {id:"S1Q1",s:1,d:1,q:"Дані продакшену показують: у 12% випадків агент пропускає get_customer і викликає lookup_order лише за іменем клієнта, що інколи призводить до помилкової ідентифікації акаунта й неправильних повернень. Яка зміна найефективніше вирішить цю проблему надійності?",opts:["Додати programmatic prerequisite, який блокує виклики lookup_order і process_refund, доки get_customer не поверне верифікований customer ID","Підсилити system prompt вимогою, що верифікація через get_customer обов'язкова перед будь-якими операціями із замовленнями","Додати few-shot приклади, де агент завжди викликає get_customer першим, навіть коли клієнт сам назвав номер замовлення","Впровадити routing-класифікатор, який вмикає лише підмножину інструментів під тип запиту"],a:0,ex:"Коли критична бізнес-логіка вимагає певної послідовності (верифікація перед поверненням коштів), programmatic enforcement дає детерміновані гарантії, яких prompt-підходи (B, C) дати не можуть через ненульову ймовірність недотримання. D вирішує доступність інструментів, а не їх порядок."},
  {id:"S1Q2",s:1,d:2,q:"Логи показують, що агент часто кличе get_customer на запити про замовлення (напр. «перевір моє замовлення #12345») замість lookup_order. Обидва інструменти мають мінімальні описи («Retrieves customer information» / «Retrieves order details») і приймають схожі формати ідентифікаторів. Який найефективніший перший крок?",opts:["Розширити опис кожного інструмента: формати входу, приклади запитів, edge cases і межі застосування відносно схожих інструментів","Додати 5–8 few-shot прикладів у system prompt, що скеровують order-запити на lookup_order","Реалізувати routing-шар, що парсить ввід і наперед обирає інструмент за ключовими словами","Об'єднати обидва інструменти в один lookup_entity, що сам визначає бекенд"],a:0,ex:"Описи інструментів — основний механізм вибору для LLM. За мінімальних описів моделі бракує контексту, щоб розрізнити схожі інструменти. B додає токени, не усуваючи причину; C — over-engineering, що обходить розуміння моделі; D — валідна, але важча архітектурна зміна, ніж потрібно для «першого кроку»."},
  {id:"S1Q3",s:1,d:5,q:"Агент дає лише 55% first-contact resolution при цілі 80%. Логи показують: він ескалює прості кейси (стандартні заміни з фото-доказом), але намагається сам обробляти складні ситуації з винятками з політики. Як найкраще покращити калібрування ескалації?",opts:["Додати у system prompt явні критерії ескалації з few-shot прикладами «коли ескалювати vs вирішувати самостійно»","Просити агента самооцінювати confidence (1–10) і автоматично маршрутизувати до людини нижче порогу","Розгорнути окрему classifier-модель на історичних тікетах, що передбачає потребу ескалації","Додати sentiment-аналіз і ескалювати при перевищенні порогу негативу"],a:0,ex:"Корінь проблеми — нечіткі межі рішення; явні критерії з прикладами б'ють прямо в нього і є пропорційним першим кроком. Самооцінка confidence (B) погано калібрована — агент уже впевнений на складних кейсах. C — over-engineering. D вирішує іншу проблему: sentiment не корелює зі складністю кейсу."},
  {id:"S1Q4",s:1,d:1,q:"Політика вимагає, щоб повернення понад $500 НІКОЛИ не виконувались автоматично, а йшли на людину. Зараз ця вимога описана в system prompt, але зрідка порушується. Що дасть детерміновану гарантію?",opts:["Hook, що перехоплює вихідний виклик process_refund і блокує суми понад $500, перенаправляючи на escalate_to_human","Чіткіше формулювання в system prompt із капіталізованим NEVER і повторенням правила","Few-shot приклади, що демонструють відмову від повернень понад $500","Зниження temperature, щоб модель суворіше дотримувалась інструкцій"],a:0,ex:"Коли бізнес-правило вимагає гарантованого дотримання, обирають hook (tool-call interception) над prompt-based підходами. B, C, D усі лишаються ймовірнісними й мають ненульовий рівень збоїв на фінансово значущих діях."},
  {id:"S1Q5",s:1,d:2,q:"Усі MCP-інструменти повертають при збої однаковий рядок «Operation failed». Через це агент однаково реагує і на таймаут, і на порушення політики, і на невалідний ввід. Як це виправити?",opts:["Повертати структуровані метадані помилки: errorCategory (transient/validation/permission), isRetryable та людиночитний опис","Додати у system prompt інструкцію завжди повторювати спробу при будь-якому «Operation failed»","Логувати помилки на бекенді детальніше, лишивши агенту той самий загальний рядок","Підвищити timeout усіх інструментів, щоб помилки траплялись рідше"],a:0,ex:"Уніфіковані помилки не дають агенту приймати правильні рішення про відновлення. Структуровані метадані (категорія, чи можна ретраїти, опис) дозволяють ретраїти transient, пояснювати business-помилки клієнту й не марнувати спроби на non-retryable. B небезпечно ретраїть усе; C/D не міняють те, що бачить агент."},
  {id:"S1Q6",s:1,d:5,q:"lookup_order повертає 40+ полів на замовлення, з яких для типового кейсу повернення релевантні лише ~5. У довгих діалогах ці виводи накопичуються й з'їдають контекст. Який підхід найкращий?",opts:["Обрізати verbose-виводи інструмента до релевантних полів ще до того, як вони потраплять у контекст","Збільшити max_tokens, щоб модель умістила всі поля","Періодично робити progressive summarization усієї історії, включно з виводами замовлень","Вимкнути lookup_order і просити клієнта диктувати деталі замовлення вручну"],a:0,ex:"Виводи інструментів накопичуються й споживають токени непропорційно до релевантності. Тримання лише потрібних полів — пряме рішення. Збільшення max_tokens (B) не стосується контексту-вікна. Агресивна сумаризація (C) ризикує втратити числа/дати. D погіршує UX."},
  {id:"S1Q7",s:1,d:5,q:"get_customer повертає кількох клієнтів, що збігаються за наданим іменем. Як агенту коректно вчинити?",opts:["Попросити додатковий ідентифікатор (email, номер замовлення), а не обирати збіг за евристикою","Обрати найновіший за датою створення акаунт як найімовірніший","Обрати акаунт з найбільшою кількістю замовлень","Об'єднати всі збіги в один профіль і продовжити"],a:0,ex:"Кілька збігів вимагають уточнення (запиту додаткових ідентифікаторів), а не евристичного вибору, бо помилкова ідентифікація веде до неправильних дій з чужим акаунтом."},
  {id:"S1Q8",s:1,d:1,q:"Клієнт пише одним повідомленням одразу про три речі: повернення коштів за пошкоджений товар, зміну адреси доставки та скаргу на затримку. Яка стратегія обробки найкраща?",opts:["Декомпозувати запит на окремі item'и, дослідити кожен (за потреби паралельно) на спільному контексті, тоді синтезувати єдину відповідь","Обробити лише перше питання (повернення), а решту попросити надіслати окремими зверненнями","Ескалювати на людину, бо багатоскладові запити поза межами агента","Відповісти загально, не викликаючи інструменти, щоб не плутати контексти"],a:0,ex:"Багатоскладові звернення декомпозують на окремі concern'и, досліджують кожен на спільному контексті й зводять у єдину резолюцію. Інші варіанти або втрачають частину запиту, або зайво ескалюють."},
  {id:"S1Q9",s:1,d:5,q:"На початку діалогу клієнт прямо й однозначно вимагає з'єднати його з живим оператором. Як вчинити агенту?",opts:["Виконати ескалацію негайно, без спроби спершу самостійно розслідувати кейс","Спершу спробувати вирішити питання, і лише якщо не вдасться — ескалювати","Запитати причину вимоги й переконати клієнта, що агент впорається","Підняти confidence-поріг і продовжити автономно"],a:0,ex:"Явну вимогу клієнта про людину виконують негайно. Це відрізняється від ситуації, де питання просте — там можна запропонувати вирішити, ескалюючи лише якщо клієнт наполягає."},
  {id:"S1Q10",s:1,d:1,q:"Різні MCP-інструменти повертають дати в різних форматах: get_customer — Unix timestamp, lookup_order — ISO 8601, а статус — числовим кодом. Це плутає модель при міркуванні. Який механізм найкращий для нормалізації?",opts:["PostToolUse hook, що нормалізує формати у виводах інструментів ще до того, як їх обробить модель","Інструкція в system prompt самостійно конвертувати всі формати дат","Окремий subagent, що переписує кожну відповідь інструмента","Few-shot приклади з різними форматами дат"],a:0,ex:"PostToolUse hook перехоплює результати інструментів і трансформує їх (нормалізація timestamp/ISO/кодів) до обробки моделлю — це детермінована нормалізація. Prompt/few-shot (B, D) лишаються ймовірнісними; окремий subagent (C) — надлишковий."},
  {id:"S1Q11",s:1,d:5,q:"У довгих діалогах ви робите progressive summarization історії. Згодом помічаєте, що агент «забуває» точну суму повернення, дату покупки й обіцянки, дані клієнту. Як це виправити?",opts:["Витягувати транзакційні факти (суми, дати, номери замовлень, статуси) в окремий persistent «case facts» блок, що додається в кожен промпт поза сумаризованою історією","Повністю відмовитись від сумаризації й завжди слати всю історію","Сумаризувати агресивніше, щоб лишалось більше місця під нові факти","Зберігати факти лише в системі логування на бекенді"],a:0,ex:"Ризик progressive summarization — згортання чисел, відсотків, дат і очікувань клієнта у розмиті формулювання. Рішення — тримати точні транзакційні факти в persistent-блоці поза сумаризованою історією. B нереалістично за токенами; C погіршує проблему; D не доходить до моделі."},
  {id:"S1Q12",s:1,d:1,q:"Ви реалізуєте agentic loop. Що має визначати, продовжувати виконувати інструменти чи завершити й показати фінальну відповідь?",opts:["stop_reason у відповіді: «tool_use» → виконати інструмент і продовжити; «end_turn» → завершити цикл","Наявність тексту в assistant-повідомленні: якщо є текст — завершити","Фіксований ліміт ітерацій як основний механізм зупинки","Парсинг фраз на кшталт «Done» / «Завершено» у відповіді моделі"],a:0,ex:"Керування циклом будують на stop_reason: продовжувати при «tool_use», завершувати при «end_turn». B, C, D — anti-patterns: перевірка тексту, жорсткий ліміт ітерацій чи парсинг natural-language сигналів ненадійні."},
  {id:"S1Q13",s:1,d:2,q:"process_refund відхиляє запит, бо сума перевищує ліміт політики (бізнес-правило, не технічний збій). Що інструмент має повернути, щоб агент відреагував коректно?",opts:["isError з retriable:false та клієнт-дружнім поясненням причини відмови","Той самий формат, що й для таймауту, щоб агент спробував ще раз","Порожній успішний результат, щоб не турбувати клієнта","HTTP 500 без додаткових метаданих"],a:0,ex:"Порушення бізнес-правила слід позначати retriable:false і додавати зрозуміле пояснення, щоб агент комунікував коректно й не ретраїв марно. Формат таймауту (B) спровокує зайві спроби; порожній успіх (C) приховує помилку; голий 500 (D) не дає контексту."},
  {id:"S1Q14",s:1,d:5,q:"Клієнт просить price-match під ціну конкурента. Політика описує лише коригування під власні попередні ціни магазину й нічого не каже про конкурентів. Що має зробити агент?",opts:["Ескалювати, бо політика мовчить/неоднозначна щодо саме цього запиту","Відмовити, бо якщо не написано — значить заборонено","Погодити price-match, бо явної заборони немає","Самостійно вигадати розумний відсоток знижки як компроміс"],a:0,ex:"Коли політика неоднозначна або мовчить щодо конкретного запиту — це тригер ескалації (policy gap), а не лише складність кейсу. Самостійне рішення (B, C, D) ризикує суперечити майбутній політиці."},
  {id:"S1Q15",s:1,d:1,q:"Колега пропонує завершувати agentic loop, коли модель згенерувала текстову відповідь без виклику інструмента, АБО після 10 ітерацій «про всяк випадок». Чому це проблема?",opts:["Це anti-patterns: перевірка тексту й жорсткий ліміт ітерацій ненадійні; зупинку слід базувати на stop_reason == «end_turn»","Проблеми немає — це стандартний рекомендований підхід","Проблема лише в ліміті 10; з лімітом 50 підхід коректний","Текст треба парсити регулярками на ключові слова завершення — тоді надійно"],a:0,ex:"Парсинг тексту, ліміт ітерацій як основний стоп і перевірка наявності тексту — класичні anti-patterns. Коректне завершення — за stop_reason «end_turn». Зміна порогу (C) чи регулярки (D) не роблять підхід надійним."},
  {id:"S1Q16",s:1,d:2,q:"Команда поступово дала агенту 18 інструментів. Тепер він почав плутатись у виборі й інколи бере не той інструмент. Який принцип допоможе найбільше?",opts:["Звузити набір інструментів до 4–5, релевантних ролі агента, бо надлишок збільшує складність рішення й знижує надійність вибору","Додати ще інструментів-«хелперів», щоб у моделі завжди був точний інструмент під кейс","Перейменувати всі 18 інструментів у коротші назви","Завжди форсувати tool_choice на перший інструмент у списку"],a:0,ex:"Завелика кількість інструментів (18 замість 4–5) деградує надійність вибору, бо зростає складність рішення. Звуження набору під роль — пряме рішення. Додавання інструментів (B) погіршує; перейменування (C) не міняє кількість; форсування першого (D) ламає логіку."},
  // SCENARIO 2
  {id:"S2Q1",s:2,d:3,q:"Ви хочете створити custom-команду /review, що запускає стандартний чек-лист код-рев'ю команди. Вона має бути доступна кожному розробнику після clone/pull репозиторію. Де створити файл команди?",opts:["У директорії .claude/commands/ у репозиторії проєкту","У ~/.claude/commands/ у домашній директорії кожного розробника","У файлі CLAUDE.md у корені проєкту","У .claude/config.json з масивом commands"],a:0,ex:"Project-scoped slash-команди зберігають у .claude/commands/ репозиторію — вони версіонуються й доступні всім після clone/pull. B — це особисті команди (не шеряться); CLAUDE.md (C) — для контексту, не для команд; D описує неіснуючий у Claude Code механізм."},
  {id:"S2Q2",s:2,d:3,q:"Вам доручили реструктуризувати моноліт у мікросервіси: зміни в десятках файлів і рішення про межі сервісів та залежності модулів. Який підхід обрати?",opts:["Увійти в plan mode: дослідити кодбазу, зрозуміти залежності й спроєктувати підхід ще до змін","Почати з direct execution й міняти інкрементально, дозволивши реалізації виявити природні межі","Direct execution з повними наперед інструкціями, як саме структурувати кожен сервіс","Почати в direct execution і перемкнутись у plan mode лише якщо виникне несподівана складність"],a:0,ex:"Plan mode створений саме для масштабних змін, кількох валідних підходів та архітектурних рішень. Він дозволяє безпечно дослідити код перед комітом до змін. B ризикує дорогими переробками; C припускає готову відповідь без дослідження; D ігнорує, що складність уже задана вимогами."},
  {id:"S2Q3",s:2,d:3,q:"Ви фіксите один баг у єдиному файлі з чітким stack trace, що прямо вказує на місце. Який режим оптимальний?",opts:["Direct execution — зміна добре зрозуміла й чітко обмежена за scope","Plan mode — будь-яка зміна коду потребує попереднього планування","Plan mode із залученням Explore subagent для повного аналізу кодбази","Спершу fork_session, потім direct execution"],a:0,ex:"Для простих, добре окреслених змін (single-file fix з чітким stack trace) пасує direct execution. Plan mode потрібен для архітектурних/багатофайлових задач, тож тут він був би надлишковим."},
  {id:"S2Q4",s:2,d:3,q:"Новий член команди скаржиться, що Claude Code не застосовує командні інструкції, які працюють у всіх інших. Ви з'ясовуєте, що інструкції лежать у ~/.claude/CLAUDE.md одного з інженерів. У чому причина й виправлення?",opts:["User-level конфіг (~/.claude/CLAUDE.md) не шериться через version control; перенести інструкції у project-level (.claude/CLAUDE.md або кореневий CLAUDE.md)","Це баг кешу; новому інженеру треба перевстановити Claude Code","Інструкції треба продублювати в кожному ~/.claude/CLAUDE.md вручну для всіх","Перенести інструкції у .gitignore, щоб вони підхопились автоматично"],a:0,ex:"Налаштування user-level застосовуються лише до цього користувача й не шеряться через VCS. Командні стандарти мають бути project-level, щоб діяти на всіх. Ручне дублювання (C) некероване; .gitignore (D) узагалі виключає файл із репозиторію."},
  {id:"S2Q5",s:2,d:3,q:"Ваш CLAUDE.md розрісся до сотень рядків і став важко підтримуваним. Який підхід рекомендований для модульності?",opts:["Розбити на тематичні файли у .claude/rules/ (напр. testing.md, api-conventions.md, deployment.md) або підключати зовнішні файли через @import","Стиснути файл, видаливши коментарі й пробіли","Перенести весь вміст у єдиний гігантський system prompt","Створити по копії повного CLAUDE.md у кожній піддиректорії"],a:0,ex:"Великий CLAUDE.md дробиться на тематичні файли у .claude/rules/ або підключається через @import-синтаксис для модульності. Стиснення (B) не вирішує підтримуваність; єдиний system prompt (C) і копії в кожній теці (D) лише погіршують."},
  {id:"S2Q6",s:2,d:3,q:"Ви прозою описуєте бажану трансформацію коду, але Claude інтерпретує її щоразу по-різному. Що найефективніше комунікує очікування?",opts:["Надати 2–3 конкретні приклади вхід/вихід, що демонструють потрібну трансформацію","Переписати інструкцію ще детальнішою прозою з більшою кількістю прикметників","Підвищити max_tokens, щоб модель докладніше пояснювала кроки","Додати в кінці інструкції фразу «будь дуже точним»"],a:0,ex:"Коли прозовий опис трактується непослідовно, найдієвіше — конкретні приклади вхід/вихід. Більше прози (B), більший max_tokens (C) чи заклики «будь точним» (D) не усувають неоднозначності так, як приклади."},
  {id:"S2Q7",s:2,d:5,q:"Під час тривалої сесії дослідження великої кодбази Claude починає давати непослідовні відповіді й посилатися на «типові патерни» замість конкретних класів, знайдених раніше. Як протидіяти цій деградації контексту?",opts:["Вести scratchpad-файл із ключовими знахідками й звертатися до нього в наступних питаннях","Просто перезапустити сесію з нуля при кожному новому питанні","Підвищити temperature, щоб відповіді стали різноманітнішими","Ігнорувати — це нормальна поведінка для довгих сесій"],a:0,ex:"У розширених сесіях контекст деградує (модель «зісковзує» на типові патерни). Scratchpad-файли з ключовими знахідками, на які агент спирається далі, допомагають це компенсувати. Повний рестарт щоразу (B) втрачає прогрес; temperature (C) не стосується; ігнорування (D) лишає проблему."},
  {id:"S2Q8",s:2,d:3,q:"Ви реалізуєте кешування у незнайомому домені й не впевнені, які грані врахували. Який прийом найкраще виявить непомічені міркування ще до реалізації?",opts:["Interview pattern: попросити Claude поставити вам запитання, що піднімуть приховані рішення (інвалідація кешу, режими збоїв)","Одразу попросити повну реалізацію й виправляти баги по факту","Дати лише прозовий опис і покластися на дефолти моделі","Згенерувати код двічі й обрати довшу версію"],a:0,ex:"Interview pattern — коли Claude ставить запитання, що виявляють непередбачені вами міркування (стратегії інвалідації кешу, failure modes) ще до реалізації. Це особливо корисно в незнайомих доменах. Решта варіантів пропускають цей етап виявлення."},
  {id:"S2Q9",s:2,d:3,q:"У вас є skill для аналізу кодбази, що генерує дуже багатослівний вивід і засмічує основну розмову. Яка опція frontmatter це вирішує?",opts:["context: fork — запускає skill в ізольованому sub-agent контексті, не забруднюючи основну розмову","allowed-tools: лише Read — обмежує інструменти, прибираючи зайвий вивід","argument-hint — підказує параметри, скорочуючи вивід","model: haiku — менша модель дає коротший вивід"],a:0,ex:"context: fork ізолює skill у subagent-контексті, тож його verbose-вивід не потрапляє в основну сесію. allowed-tools (B) обмежує інструменти, а не ізолює контекст; argument-hint (C) — про параметри; зміна моделі (D) не про ізоляцію."},
  {id:"S2Q10",s:2,d:5,q:"Під час тривалої багатофазної сесії контекст заповнюється багатослівним discovery-виводом, і ви бачите, що місця лишається все менше. Яка вбудована команда допоможе зменшити споживання контексту по ходу?",opts:["/compact — стискає контекст під час сесії","/reset — повністю очищає й обнуляє все","/verbose — перемикає рівень деталізації виводу","/tokens — лише показує лічильник токенів"],a:0,ex:"/compact зменшує споживання контексту у розширених сесіях, коли він заповнюється багатослівним discovery. /reset (якби існував) втратив би прогрес; /verbose і /tokens не стискають контекст."},
  {id:"S2Q11",s:2,d:3,q:"Поведінка Claude Code різниться між сесіями, і ви підозрюєте, що десь не підвантажується потрібний memory-файл. Яка команда допоможе діагностувати, які memory-файли завантажені?",opts:["/memory — показує, які memory-файли наразі завантажені","/debug — вмикає повний трейс виконання","/files — перелічує всі файли проєкту","/config — відкриває редактор глобального конфігу"],a:0,ex:"Команда /memory дозволяє перевірити, які memory-файли підвантажені, і діагностувати непослідовну поведінку між сесіями. Інші перелічені команди не дають саме цієї інформації."},
  {id:"S2Q12",s:2,d:3,q:"Ви знайшли кілька дефектів у щойно згенерованому модулі. Частина з них взаємопов'язана (виправлення одного впливає на інші), частина — незалежна. Як подавати фідбек для ітерації?",opts:["Взаємопов'язані проблеми давати одним детальним повідомленням разом; незалежні — виправляти послідовно окремими ітераціями","Завжди давати всі проблеми одним повідомленням незалежно від зв'язків","Завжди виправляти строго по одній проблемі за раз","Давати лише найкритичнішу, решту ігнорувати"],a:0,ex:"Взаємодіючі проблеми краще адресувати в одному детальному повідомленні (бо їх виправлення взаємозалежні), а незалежні — послідовно. Жорсткі «завжди разом» (B) чи «завжди по одній» (C) ігнорують характер залежностей; D лишає дефекти."},
  {id:"S2Q13",s:2,d:3,q:"Ви хочете персональний варіант командного skill з іншою поведінкою, але так, щоб НЕ зачепити колег. Як це зробити?",opts:["Створити персональний варіант у ~/.claude/skills/ під іншою назвою","Відредагувати спільний skill у .claude/skills/ репозиторію","Закомітити свою версію поверх командної в .claude/skills/","Видалити командний skill і замінити своїм"],a:0,ex:"Персональні кастомізації роблять у ~/.claude/skills/ під іншою назвою, щоб не впливати на команду. Редагування/коміт у спільний .claude/skills/ (B, C) зачепить усіх; видалення (D) тим паче."},
  {id:"S2Q14",s:2,d:3,q:"У багатофазній задачі фаза discovery дає стільки виводу, що з'їдає контекст-вікно ще до реалізації. Який механізм Claude Code це ізолює?",opts:["Explore subagent — ізолює багатослівний discovery й повертає в основну сесію лише стислий підсумок","Збільшення max_tokens основної сесії","Запуск усього в plan mode без subagent'ів","Вимкнення інструментів Read/Grep на час discovery"],a:0,ex:"Explore subagent ізолює verbose discovery-вивід і повертає підсумки, зберігаючи контекст основної розмови. Збільшення max_tokens (B) не стосується контексту-вікна; plan mode сам по собі (C) не ізолює discovery; вимкнення інструментів (D) зробить дослідження неможливим."},
  {id:"S2Q15",s:2,d:3,q:"Ви ітеративно доводите складну функцію до коректності. Який підхід найнадійніше скеровує прогресивне покращення?",opts:["Спершу написати тест-сьют (очікувана поведінка, edge cases, перформанс), потім ітерувати, ділячись падіннями тестів","Просити Claude самому оцінювати, чи код готовий, і зупинятись на його сигнал","Збільшувати довжину промпта з кожною ітерацією","Генерувати по 5 варіантів і обирати найкоротший"],a:0,ex:"Test-driven ітерація: спочатку тести, що покривають поведінку, edge cases і перформанс, далі — ітерації через шерінг падінь тестів. Це дає об'єктивний сигнал прогресу, на відміну від самооцінки моделі (B) чи довільних евристик (C, D)."},
  {id:"S2Q16",s:2,d:3,q:"Ви плануєте міграцію бібліотеки, що зачіпає 45+ файлів. Як найкраще поєднати режими роботи?",opts:["Plan mode для дослідження й вибору підходу до міграції, потім direct execution для виконання спланованого","Лише direct execution від початку до кінця заради швидкості","Лише plan mode — і для планування, і для самого внесення змін","Окрема нова сесія на кожен із 45 файлів без спільного плану"],a:0,ex:"Оптимально — поєднати plan mode для розслідування й проєктування з direct execution для реалізації спланованого підходу. Лише direct (B) ризикує переробками; лише plan (C) не виконує змін; роздроблені сесії без плану (D) втрачають цілісність."},
  // SCENARIO 3
  {id:"S3Q1",s:3,d:1,q:"Запустивши систему на темі «вплив AI на креативні індустрії», ви бачите: усі subagent'и відпрацювали успішно, але фінальні звіти охоплюють лише візуальне мистецтво й повністю пропускають музику, письменство та кіно. У логах coordinator'а: він розбив тему на «AI in digital art», «AI in graphic design», «AI in photography». Найімовірніша корінна причина?",opts:["Декомпозиція задачі coordinator'ом надто вузька — призначення subagent'ам не покривають усіх релевантних доменів теми","Synthesis-агенту бракує інструкцій виявляти прогалини покриття в отриманих знахідках","Запити web-search агента недостатньо широкі й їх треба розширити","Document-аналіз агент відфільтровує не-візуальні джерела через надто жорсткі критерії релевантності"],a:0,ex:"Логи прямо показують причину: coordinator розклав «креативні індустрії» лише на візуальні підтеми, пропустивши музику/письменство/кіно. Subagent'и коректно зробили те, що їм призначили. B, C, D помилково звинувачують нижчі агенти, які працюють у межах призначеного scope."},
  {id:"S3Q2",s:3,d:5,q:"Web-search subagent впадає в timeout на складній темі. Ви проєктуєте, як ця інформація про збій тече назад до coordinator'а. Який підхід до error propagation найкраще вмикає інтелектуальне відновлення?",opts:["Повернути coordinator'у структурований error-контекст: тип збою, який запит пробували, будь-які partial results і можливі альтернативні підходи","Реалізувати retry з exponential backoff усередині subagent'а й повернути лише «search unavailable» після вичерпання спроб","Перехопити timeout і повернути порожній результат, позначений як успішний","Прокинути timeout-виняток у top-level handler, що завершує весь research-воркфлоу"],a:0,ex:"Структурований error-контекст дає coordinator'у дані для розумного рішення (ретрай з модифікацією, альтернатива, чи продовжити з partial results). Загальний статус (B) ховає контекст; «успіх» при збої (C) приховує помилку; завершення всього воркфлоу (D) надмірне."},
  {id:"S3Q3",s:3,d:2,q:"Synthesis-агент часто має перевіряти конкретні факти, повертаючи керування coordinator'у → web-search → знову synthesis (+2–3 round trips, +40% latency). 85% перевірок — прості факт-чеки (дати, імена, статистика), 15% — глибше дослідження. Як зменшити overhead, зберігши надійність?",opts:["Дати synthesis-агенту scoped-інструмент verify_fact для простих lookup'ів, а складні верифікації лишити делегованими через coordinator","Накопичувати всі потреби верифікації й батчем повертати coordinator'у в кінці проходу","Дати synthesis-агенту повний доступ до всіх web-search інструментів","Web-search агент має проактивно кешувати додатковий контекст навколо кожного джерела «про запас»"],a:0,ex:"Принцип найменших привілеїв: scoped verify_fact покриває 85% простих кейсів, а складні лишаються в наявному патерні координації. Батч (B) створює блокуючі залежності; повний доступ (C) порушує separation of concerns; спекулятивний кеш (D) не передбачить потреби надійно."},
  {id:"S3Q4",s:3,d:1,q:"Synthesis-subagent видає звіти так, ніби не бачив знахідок web-search і document-агентів. Coordinator їх викликав, але synthesis «не знає» їхніх результатів. Найімовірніша причина?",opts:["Subagent'и не успадковують контекст автоматично — знахідки попередніх агентів треба явно передавати у промпт synthesis-агента","Synthesis-агенту бракує доступу до інструмента Task","Координатор використовує застарілу версію SDK","Потрібно підвищити max_tokens synthesis-агента"],a:0,ex:"Subagent'и працюють з ізольованим контекстом і не успадковують історію coordinator'а; контекст треба явно вкладати у промпт (напр. передати synthesis-агенту результати пошуку й аналізу). Інші варіанти не стосуються причини."},
  {id:"S3Q5",s:3,d:1,q:"Coordinator має запустити трьох незалежних subagent'ів одночасно, щоб скоротити час. Як це зробити правильно?",opts:["Емітувати кілька викликів Task в одній відповіді coordinator'а, щоб subagent'и стартували паралельно","Викликати Task по одному в окремих ходах і чекати завершення кожного перед наступним","Створити один subagent, що всередині послідовно зробить три задачі","Підняти temperature, щоб coordinator «захотів» паралелити"],a:0,ex:"Паралельний запуск роблять, емітуючи кілька викликів Task в одній відповіді coordinator'а, а не в окремих ходах. Послідовні виклики (B) чи один subagent на все (C) не дають паралелізму; temperature (D) тут ні до чого."},
  {id:"S3Q6",s:3,d:1,q:"Coordinator-агент не може запустити жодного subagent'а — виклики просто не відбуваються. Що найімовірніше треба перевірити в його конфігурації?",opts:["Чи містить allowedTools інструмент «Task» — він обов'язковий, щоб coordinator міг спавнити subagent'ів","Чи увімкнено streaming у відповідях coordinator'а","Чи однакова модель у coordinator'а й subagent'ів","Чи достатній max_tokens для відповіді subagent'а"],a:0,ex:"Механізм спавну subagent'ів — інструмент Task; щоб coordinator міг їх викликати, його allowedTools має включати «Task». Streaming/модель/max_tokens (B, C, D) не блокують саму можливість спавну."},
  {id:"S3Q7",s:3,d:5,q:"Після кроку синтезу у фінальному звіті губиться, з якого саме джерела взято кожне твердження. Як зберегти провенанс через синтез?",opts:["Вимагати від subagent'ів структуровані claim-source мапінги (URL/назва документа, релевантний уривок), які downstream-агенти зобов'язані зберігати й зливати при синтезі","Додати в кінці звіту загальний список усіх використаних джерел без прив'язки до тверджень","Просити synthesis-агента вгадати джерело за стилем тексту","Зберігати джерела лише в логах, не в контексті агентів"],a:0,ex:"Атрибуцію втрачають під час сумаризації, коли стискають без збереження claim-source зв'язків. Рішення — структуровані claim-source мапінги, які synthesis зберігає й зливає. Загальний список без прив'язки (B), вгадування (C) чи логи поза контекстом (D) не зберігають провенанс на рівні тверджень."},
  {id:"S3Q8",s:3,d:5,q:"Два авторитетні джерела дають різну статистику по одному показнику. Як synthesis-агент має вчинити?",opts:["Зберегти обидва значення з атрибуцією джерел, явно позначивши конфлікт, а не довільно обирати одне","Обрати значення з джерела, що згадане першим","Усереднити два значення в одне число","Відкинути обидва значення як ненадійні"],a:0,ex:"Конфліктні дані з авторитетних джерел анотують із зазначенням джерел, а не обирають довільно. Вибір першого (B), усереднення (C) чи відкидання (D) спотворюють картину й приховують реальний конфлікт."},
  {id:"S3Q9",s:3,d:1,q:"Coordinator завжди проганяє повний пайплайн (усі subagent'и) навіть для простих запитів, що марнує час і токени. Як це покращити?",opts:["Проєктувати coordinator так, щоб він аналізував вимоги запиту й динамічно обирав, яких subagent'ів викликати, а не завжди йшов повним маршрутом","Прибрати coordinator і дати агентам спілкуватися напряму між собою","Зробити всіх subagent'ів обов'язковими, але прискорити їх","Кешувати відповіді й повертати їх на будь-який запит"],a:0,ex:"Coordinator має аналізувати складність запиту й динамічно обирати потрібних subagent'ів, а не завжди гнати повний пайплайн. Прибирання coordinator'а (B) ламає hub-and-spoke; обов'язковість усіх (C) лишає марнування; сліпий кеш (D) дає некоректні відповіді."},
  {id:"S3Q10",s:3,d:5,q:"Synthesis позначає як «суперечність» дані, що насправді просто зібрані в різні роки. Як запобігти цьому хибному трактуванню?",opts:["Вимагати від subagent'ів включати дату публікації/збору даних у структуровані виводи, щоб коректно інтерпретувати темпоральні відмінності","Завжди обирати найновіше число й ігнорувати старіші","Заборонити агентам використовувати будь-які числові дані","Підвищити поріг, за яким значення вважаються суперечливими"],a:0,ex:"Темпоральні дані потребують дат публікації/збору в структурованих виводах, щоб різниця в часі не трактувалась як суперечність. Сліпий вибір найновішого (B), відмова від чисел (C) чи зміна порогу (D) не розв'язують суть."},
  {id:"S3Q11",s:3,d:1,q:"Coordinator отримав синтез, у якому є очевидні прогалини покриття теми. Який патерн найкраще це лікує?",opts:["Iterative refinement loop: coordinator оцінює синтез на прогалини, переделеговує search/analysis з націленими запитами й повторно викликає synthesis, доки покриття не стане достатнім","Прийняти синтез як є й позначити прогалини в кінці звіту дрібним шрифтом","Перезапустити всю систему з нуля на ту саму тему","Збільшити кількість subagent'ів удвічі для всіх майбутніх запитів"],a:0,ex:"Iterative refinement: coordinator виявляє прогалини, переделеговує цільові запити й повторно синтезує, поки покриття не достатнє. Прийняти як є (B) лишає прогалини; повний рестарт (C) і подвоєння агентів (D) — неефективні й не цільові."},
  {id:"S3Q12",s:3,d:5,q:"Один subagent при збої повертає порожній результат, позначений як «успішний», щоб не «ламати» пайплайн. Чому це anti-pattern і що робити натомість?",opts:["Це приховує помилку (мовчазне придушення); треба розрізняти access failure (збій доступу, потребує рішення про ретрай) і валідний empty result (успішний запит без збігів)","Усе гаразд — порожній успіх спрощує обробку в coordinator'а","Треба навпаки: завершувати весь воркфлоу при будь-якому збої subagent'а","Достатньо логувати збій, лишивши агенту статус «успіх»"],a:0,ex:"Мовчазне придушення помилок (empty як success) і завершення всього воркфлоу на один збій — обидва anti-patterns. Коректно — розрізняти access failure від валідного empty result, щоб coordinator приймав правильні рішення. Логи поза контекстом (D) агенту не допомагають."},
  {id:"S3Q13",s:3,d:5,q:"Synthesis-агент має обмежений бюджет контексту, а upstream-агенти повертають багатослівні reasoning-ланцюги й сирий контент. Як це оптимізувати?",opts:["Модифікувати upstream-агентів, щоб вони повертали структуровані дані (ключові факти, цитати, relevance scores) замість verbose-контенту й reasoning-ланцюгів","Збільшити max_tokens synthesis-агента до максимуму","Прибрати synthesis-крок і зливати тексти конкатенацією","Перенести весь reasoning у system prompt synthesis-агента"],a:0,ex:"Коли downstream має обмежений бюджет, upstream-агенти мають повертати структуровані дані (факти, цитати, relevance) замість багатослівного контенту й reasoning. Збільшення max_tokens (B) не масштабується; конкатенація (C) втрачає синтез; перенос reasoning (D) лише роздуває контекст."},
  {id:"S3Q14",s:3,d:1,q:"Команда хоче кращої спостережуваності й узгодженої обробки помилок у багатоагентній системі. Як організувати комунікацію subagent'ів?",opts:["Маршрутизувати всю комунікацію subagent'ів через coordinator (hub-and-spoke) для спостережуваності, єдиної обробки помилок і контрольованого потоку інформації","Дозволити subagent'ам напряму викликати одне одного для швидкості","Зробити спільну глобальну пам'ять, до якої пишуть усі агенти одночасно","Прибрати coordinator, лишивши лінійний ланцюг агентів"],a:0,ex:"Hub-and-spoke: coordinator керує всією міжагентною комунікацією, обробкою помилок і маршрутизацією — це дає спостережуваність і контроль. Прямі виклики (B), спільна глобальна пам'ять (C) чи лінійний ланцюг без координатора (D) погіршують контроль і трасування."},
  {id:"S3Q15",s:3,d:2,q:"Synthesis-агент час від часу намагається сам робити веб-пошуки й використовує інструменти поза своєю спеціалізацією, псуючи результат. Який принцип розподілу інструментів допоможе?",opts:["Обмежити набір інструментів кожного subagent'а тими, що релевантні його ролі, запобігаючи cross-specialization misuse","Дати всім subagent'ам однаковий повний набір інструментів для гнучкості","Прибрати в synthesis-агента всі інструменти взагалі","Форсувати tool_choice synthesis-агента на web-search"],a:0,ex:"Агенти з інструментами поза спеціалізацією схильні їх неправильно вживати. Рішення — scoped tool access: лише потрібні ролі інструменти. Повний набір усім (B) погіршує; повне позбавлення (C) зламає synthesis; форсування web-search (D) узагалі помилкове."},
  {id:"S3Q16",s:3,d:1,q:"Як краще написати промпт coordinator'а для subagent'ів, щоб ті лишались адаптивними?",opts:["Задавати дослідницькі цілі та критерії якості, а не покрокові процедурні інструкції","Прописувати точний step-by-step сценарій кожного subagent'а","Давати лише назву теми без жодних критеріїв","Жорстко фіксувати кількість джерел і слів для кожного агента"],a:0,ex:"Промпти coordinator'а мають специфікувати дослідницькі цілі й критерії якості, а не покрокові процедури — це лишає subagent'ам простір для адаптації. Жорсткий step-by-step (B) і жорсткі ліміти (D) сковують; гола тема без критеріїв (C) дає неконтрольований результат."},
  // SCENARIO 4
  {id:"S4Q1",s:4,d:2,q:"Інженер просить знайти всі місця виклику конкретної функції по кодбазі. Який built-in інструмент обрати?",opts:["Grep — пошук за вмістом файлів (імена функцій, повідомлення помилок, import'и)","Glob — пошук файлів за патерном імені/розширення","Read — читати кожен файл цілком по черзі","Bash із інтерактивним редактором"],a:0,ex:"Grep призначений для пошуку за вмістом коду (напр. усі виклики функції). Glob (B) шукає файли за патерном імені; Read (C) читає вміст конкретного файлу, не шукає по всіх; Bash-редактор (D) недоречний."},
  {id:"S4Q2",s:4,d:2,q:"Потрібно знайти всі тестові файли за патерном **/*.test.tsx по проєкту. Який інструмент пасує?",opts:["Glob — пошук шляхів файлів за патерном імені/розширення","Grep — пошук за вмістом усередині файлів","Edit — точкова зміна за унікальним текстом","Write — створення нових файлів"],a:0,ex:"Glob знаходить файли за патернами імен (напр. **/*.test.tsx). Grep (B) — для вмісту; Edit (C) і Write (D) — для модифікації/створення, не для пошуку."},
  {id:"S4Q3",s:4,d:2,q:"Edit падає, бо текст-якір, який ви хочете замінити, зустрічається в файлі неунікально. Який надійний fallback?",opts:["Прочитати файл цілком через Read, тоді переписати через Write","Кілька разів повторити Edit, доки не спрацює","Видалити файл і створити заново наосліп","Перейти на Grep для зміни вмісту"],a:0,ex:"Коли Edit не може знайти унікальний якір, надійний fallback — Read (завантажити повний вміст) + Write (перезаписати). Повтори Edit (B) не усунуть неунікальність; видалення наосліп (C) ризиковане; Grep (D) не редагує."},
  {id:"S4Q4",s:4,d:2,q:"Агент має зрозуміти незнайому кодбазу. Який підхід до дослідження найефективніший за контекстом?",opts:["Інкрементально: спершу Grep, щоб знайти точки входу, далі Read, щоб іти за import'ами й трасувати потоки","Прочитати всі файли проєкту наперед через Read, щоб мати повну картину","Покластися лише на назви файлів через Glob без читання вмісту","Виконати Bash-скрипт, що друкує весь код у консоль"],a:0,ex:"Розуміння будують інкрементально: Grep для точок входу, потім Read для трасування import'ів і потоків — а не читання всіх файлів наперед (B), що з'їдає контекст. Лише імена (C) недостатні; дамп усього коду (D) теж переповнює контекст."},
  {id:"S4Q5",s:4,d:2,q:"Команда хоче спільний MCP-сервер з автентифікацією токеном, доступний усім у проєкті, без коміту секретів у репозиторій. Як налаштувати?",opts:["Сконфігурувати сервер у project-scoped .mcp.json з expansion змінних оточення (напр. ${GITHUB_TOKEN}) для токена","Захардкодити токен прямо в .mcp.json і закомітити","Покласти конфіг у ~/.claude.json кожного розробника окремо","Передавати токен у тексті кожного промпта вручну"],a:0,ex:"Спільні командні MCP-сервери конфігурують у project-scoped .mcp.json з expansion змінних оточення для токенів — секрети не комітяться. Хардкод (B) витікає в репозиторій; user-scope (C) не шериться як командний; ручна передача в промпті (D) небезпечна й непрактична."},
  {id:"S4Q6",s:4,d:2,q:"Розробник хоче підключити особистий експериментальний MCP-сервер лише для себе, не зачіпаючи команду. Куди його прописати?",opts:["У user-scoped ~/.claude.json","У project-scoped .mcp.json репозиторію","У кореневий CLAUDE.md проєкту","У .claude/commands/ як slash-команду"],a:0,ex:"Особисті/експериментальні MCP-сервери прописують у user-scoped ~/.claude.json. Project-scoped .mcp.json (B) зробив би його командним; CLAUDE.md (C) і commands (D) — не місце для MCP-конфігурації."},
  {id:"S4Q7",s:4,d:2,q:"Ви додали потужний MCP-інструмент пошуку, але агент усе одно віддає перевагу built-in Grep і майже не кличе ваш інструмент. Який найкращий перший крок?",opts:["Покращити опис MCP-інструмента, детально пояснивши його можливості й виводи, щоб агент не надавав перевагу built-in","Видалити інструмент Grep у агента взагалі","Форсувати tool_choice завжди на MCP-інструмент","Перейменувати Grep, щоб заплутати агента"],a:0,ex:"Якщо агент віддає перевагу built-in над кращим MCP-інструментом, підсилюють опис MCP-інструмента (можливості, виводи), щоб він став очевидним вибором. Видалення Grep (B) і форсування (C) — грубі обхідні шляхи; перейменування Grep (D) — anti-pattern."},
  {id:"S4Q8",s:4,d:2,q:"Агент щоразу робить багато exploratory-викликів, щоб дізнатися, які дані взагалі доступні (перелік issue, ієрархія документації, схеми БД). Що зменшить ці зайві виклики?",opts:["Виставити каталоги контенту як MCP resources, щоб дати агенту видимість доступних даних без exploratory-викликів","Збільшити max_tokens, щоб умістити більше результатів пошуку","Додати ще інструментів пошуку для кожного типу даних","Кешувати результати exploratory-викликів на бекенді"],a:0,ex:"MCP resources — механізм виставити каталоги контенту (issue summaries, ієрархії документації, схеми БД), щоб агент бачив доступні дані без exploratory tool calls. Інші варіанти не дають цієї оглядовості наперед."},
  {id:"S4Q9",s:4,d:2,q:"Вам потрібна стандартна інтеграція з Jira. Що краще — писати власний MCP-сервер чи взяти готовий?",opts:["Узяти існуючий community MCP-сервер для стандартної інтеграції, лишивши кастомні сервери для team-specific воркфлоу","Завжди писати власний сервер заради повного контролю","Не використовувати MCP, а парсити Jira через Bash і curl","Виставити Jira як CLAUDE.md-файл"],a:0,ex:"Для стандартних інтеграцій (напр. Jira) обирають готові community MCP-сервери, а кастомні лишають для специфічних командних воркфлоу. Завжди-власний (B) — зайва робота; Bash-парсинг (C) крихкий; CLAUDE.md (D) не для цього."},
  {id:"S4Q10",s:4,d:1,q:"Задача: «додати вичерпні тести до великої legacy-кодбази». Це відкрита задача без наперед відомого плану. Яка стратегія декомпозиції підходить?",opts:["Dynamic adaptive decomposition: спершу зкартувати структуру, виявити high-impact зони, тоді скласти пріоритезований план, що адаптується в міру виявлення залежностей","Fixed sequential pipeline із наперед заданими кроками для всіх файлів","Згенерувати тести для всіх файлів одним проходом без плану","Просити користувача наперед перелічити всі потрібні тести"],a:0,ex:"Відкриті дослідницькі задачі вимагають динамічної адаптивної декомпозиції: мапа структури → high-impact зони → пріоритезований план, що адаптується. Fixed pipeline (B) пасує передбачуваним задачам; one-pass без плану (C) і повний список наперед (D) тут нереалістичні."},
  {id:"S4Q11",s:4,d:1,q:"Вам треба передбачуваний багатоаспектний code review: проаналізувати кожен файл окремо, а потім зробити окремий крос-файловий інтеграційний прохід. Який патерн декомпозиції це?",opts:["Prompt chaining — фіксований послідовний пайплайн із чітких кроків","Dynamic decomposition на основі проміжних знахідок","Single-pass аналіз усього разом","Fork-based exploration кількох гілок"],a:0,ex:"Для передбачуваних багатоаспектних рев'ю пасує prompt chaining — фіксована послідовність кроків (напр. аналіз кожного файлу, тоді крос-файловий прохід). Dynamic decomposition (B) — для відкритих задач; single-pass (C) дає attention dilution; fork (D) — про дивергентні гілки."},
  {id:"S4Q12",s:4,d:1,q:"Ви повертаєтесь до конкретної названої сесії розслідування, щоб продовжити її через день. Який механізм використати?",opts:["--resume <session-name>, щоб продовжити саме цю названу попередню розмову","fork_session, щоб створити нову гілку","/compact на поточній сесії","Почати нову сесію без жодного контексту"],a:0,ex:"Названу сесію продовжують через --resume <session-name>. fork_session (B) — для дивергентних гілок від спільної бази; нова сесія без контексту (D) втрачає напрацювання; /compact (C) лише стискає поточний контекст."},
  {id:"S4Q13",s:4,d:1,q:"Ви хочете порівняти два підходи до рефакторингу, стартуючи з однакового базового аналізу кодбази, але в незалежних гілках. Що використати?",opts:["fork_session — створити незалежні гілки від спільного analysis baseline для дивергентних підходів","--resume однієї й тієї ж сесії для обох підходів по черзі","Дві повністю незалежні сесії з нуля без спільної бази","/memory, щоб роздвоїти контекст"],a:0,ex:"fork_session створює незалежні гілки від спільного baseline — ідеально для порівняння двох стратегій рефакторингу. --resume однієї сесії (B) змішає гілки; дві сесії з нуля (C) втрачають спільну базу; /memory (D) не про форк."},
  {id:"S4Q14",s:4,d:1,q:"Ви відновлюєте сесію після того, як кілька раніше проаналізованих файлів були змінені поза Claude. Як діяти найнадійніше?",opts:["Поінформувати відновлену сесію про конкретні зміни файлів для націленого ре-аналізу; якщо ж попередні tool-результати застаріли загалом — почати свіжу сесію з ін'єкцією структурованого summary","Просто продовжити --resume і покластися на старі tool-результати як є","Завжди починати з нуля, ігноруючи весь попередній контекст","Підвищити max_tokens, щоб умістити і старий, і новий стан"],a:0,ex:"Важливо повідомити агенту про зміни файлів для цільового ре-аналізу; коли попередні tool-результати застаріли, надійніше почати свіжу сесію зі структурованим summary, ніж resume зі stale-даними. Сліпий resume (B) ризикує діяти на застарілому; завжди-з-нуля (C) марнує валідний контекст; max_tokens (D) не про свіжість даних."},
  {id:"S4Q15",s:4,d:2,q:"У вас є один загальний інструмент analyze_document, який модель застосовує по-різному й непослідовно. Який рефакторинг покращить надійність?",opts:["Розбити його на purpose-specific інструменти з чіткими input/output контрактами (напр. extract_data_points, summarize_content, verify_claim_against_source)","Лишити один інструмент, але збільшити його опис удвічі","Об'єднати його ще з кількома інструментами в один універсальний","Форсувати tool_choice завжди на analyze_document"],a:0,ex:"Загальні інструменти розбивають на purpose-specific із визначеними контрактами — це усуває неоднозначність застосування. Просто довший опис (B) не міняє суті generic-інструмента; об'єднання (C) погіршує; форсування (D) не вирішує плутанину застосування."},
  {id:"S4Q16",s:4,d:2,q:"Ви хочете гарантувати, що модель викличе якийсь інструмент, а не поверне просто текстову відповідь. Яке налаштування tool_choice використати?",opts:["tool_choice: \"any\" — модель зобов'язана викликати інструмент (хоч і сама обирає який)","tool_choice: \"auto\" — модель може повернути текст замість виклику","tool_choice: {\"type\":\"tool\",\"name\":\"...\"} обов'язково з конкретним інструментом, навіть якщо він не той","Прибрати всі інструменти, щоб лишився лише текст"],a:0,ex:"tool_choice: \"any\" гарантує, що модель викличе якийсь інструмент, а не поверне conversational-текст. \"auto\" (B) дозволяє текст; форсування конкретного (C) недоречне, якщо потрібен будь-який; прибирання інструментів (D) — протилежне меті."},
  // SCENARIO 5
  {id:"S5Q1",s:5,d:3,q:"Ваш pipeline-скрипт запускає claude \"Analyze this PR for security issues\", але job висить нескінченно — Claude Code чекає на інтерактивний ввід. Який правильний підхід для автоматизованого пайплайну?",opts:["Додати прапорець -p: claude -p \"Analyze this PR for security issues\"","Виставити змінну оточення CLAUDE_HEADLESS=true перед запуском","Перенаправити stdin з /dev/null","Додати прапорець --batch"],a:0,ex:"Прапорець -p (--print) — задокументований спосіб запуску Claude Code в неінтерактивному режимі: обробляє промпт, друкує в stdout і виходить. CLAUDE_HEADLESS (B) і --batch (D) — неіснуючі; редирект stdin (C) — обхід, що не відповідає синтаксису Claude Code."},
  {id:"S5Q2",s:5,d:4,q:"Команда хоче зменшити витрати на API. Зараз real-time виклики живлять два воркфлоу: (1) блокуючий pre-merge check, який має завершитись до merge, і (2) звіт по tech debt, що генерується вночі для ранкового перегляду. Менеджер пропонує перевести обидва на Message Batches API заради 50% економії. Як оцінити?",opts:["Перевести на batch лише звіти по tech debt; для pre-merge checks лишити real-time","Перевести обидва на batch зі status polling","Лишити real-time для обох, щоб уникнути проблем із порядком результатів","Перевести обидва на batch із timeout-fallback на real-time"],a:0,ex:"Batches API дає 50% економії, але час обробки — до 24 годин без гарантії latency. Це не годиться для блокуючого pre-merge, але ідеально для нічних звітів. B покладається на «зазвичай швидше» — неприйнятно для блокуючого; C — хибне уявлення (результати корелюються через custom_id); D — зайва складність."},
  {id:"S5Q3",s:5,d:4,q:"PR змінює 14 файлів у модулі обліку. Single-pass рев'ю всіх файлів разом дає непослідовний результат: десь детальний фідбек, десь поверхневий, очевидні баги пропущені, а інколи фідбек суперечливий — патерн позначено проблемним в одному файлі й схвалено ідентичний код в іншому. Як перебудувати рев'ю?",opts:["Розбити на сфокусовані проходи: аналіз кожного файлу окремо на локальні проблеми, потім окремий integration-прохід по крос-файлових потоках даних","Вимагати від розробників ділити великі PR на 3–4 файли перед авто-рев'ю","Перейти на модель із більшим контекстним вікном, щоб умістити всі 14 файлів за раз","Зробити три незалежні проходи й флагати лише ті проблеми, що з'явились мінімум у двох"],a:0,ex:"Корінь — attention dilution при обробці багатьох файлів разом. Розбиття на per-file проходи + окремий integration-прохід дає рівну глибину й ловить крос-файлові проблеми. B перекладає тягар на людей; C — хибне уявлення (більший контекст ≠ краща увага); D придушує реальні баги, які ловляться лише інколи."},
  {id:"S5Q4",s:5,d:3,q:"Ви хочете, щоб у CI Claude Code видавав машиночитні findings для автоматичного постингу як inline-коментарі до PR. Які CLI-прапорці це забезпечують?",opts:["--output-format json разом із --json-schema для структурованого виводу","--verbose для повного тексту з подальшим парсингом регулярками","--interactive, щоб уточнити формат у діалозі","--markdown для красивого форматування коментарів"],a:0,ex:"--output-format json із --json-schema продукують машиночитні структуровані findings для автоматичного постингу як inline PR-коментарі. Verbose+regex (B) крихке; --interactive (C) повісить CI; --markdown (D) не дає надійної структури для парсингу."},
  {id:"S5Q5",s:5,d:4,q:"Ваш промпт каже «перевір, що коментарі точні», і це дає багато false positives. Як переформулювати критерій, щоб підвищити точність?",opts:["Дати явний критерій: «флагати коментар, лише коли заявлена в ньому поведінка суперечить фактичній поведінці коду»","Додати «будь консервативним і повідомляй лише high-confidence знахідки»","Просити модель самій оцінювати впевненість і фільтрувати за нею","Збільшити max_tokens, щоб модель ретельніше перевіряла"],a:0,ex:"Явні категоріальні критерії («флагати, лише коли заявлене суперечить реальній поведінці») працюють краще за розмиті інструкції. Загальні «будь консервативним / лише high-confidence» (B, C) не підвищують точність так, як конкретні критерії; max_tokens (D) не про це."},
  {id:"S5Q6",s:5,d:4,q:"Менеджер пропонує знизити false positives, додавши в промпт «звітуй лише про high-confidence проблеми» та «будь обережним». Чому це слабке рішення?",opts:["Загальні інструкції на кшталт «будь консервативним» чи «лише high-confidence» не підвищують precision; потрібні конкретні категоріальні критерії, що визначають, які проблеми звітувати, а які пропускати","Це сильне рішення — саме так і треба робити","Проблема лише в слові «обережним»; досить замінити його на «суворим»","Достатньо знизити temperature до нуля"],a:0,ex:"Розмиті заклики до обережності/впевненості не покращують precision. Дієве — специфічні категоріальні критерії: що саме звітувати (баги, security) і що пропускати (дрібний стиль). Заміна слів (C) чи temperature (D) суті не міняють."},
  {id:"S5Q7",s:5,d:4,q:"Та сама Claude-сесія, що згенерувала код, гірше знаходить у ньому власні тонкі помилки, навіть з інструкцією «перевір себе» чи extended thinking. Який підхід ефективніший?",opts:["Використати другий незалежний інстанс Claude (без reasoning-контексту генерації) для рев'ю коду","Додати в той самий промпт інструкцію «уважно перевір власний код двічі»","Увімкнути extended thinking у тій самій сесії","Підняти temperature на етапі самоперевірки"],a:0,ex:"Модель зберігає reasoning-контекст генерації й менш схильна сумніватись у власних рішеннях у тій самій сесії. Незалежний review-інстанс без цього контексту ефективніше ловить тонкі проблеми, ніж self-review інструкції (B), extended thinking (C) чи temperature (D)."},
  {id:"S5Q8",s:5,d:3,q:"Після нових комітів ви повторно ганяєте рев'ю, і Claude постить дублікати коментарів на ті самі проблеми, що вже були. Як це усунути?",opts:["Включати попередні findings у контекст і інструктувати Claude звітувати лише нові або досі невиправлені проблеми","Видаляти всі попередні коментарі перед кожним повторним рев'ю","Запускати рев'ю лише раз на весь PR і більше ніколи","Знизити max_tokens, щоб коментарів фізично було менше"],a:0,ex:"При повторних рев'ю після нових комітів передають попередні findings у контекст і просять звітувати лише нові/невиправлені — це уникає дублів. Видалення коментарів (B) втрачає історію; одноразове рев'ю (C) ламає процес; менший max_tokens (D) ріже зміст наосліп."},
  {id:"S5Q9",s:5,d:4,q:"Детальні інструкції все одно дають непослідовний формат фідбеку рев'ю. Який прийом найкраще дає консистентний, actionable формат?",opts:["Few-shot приклади, що демонструють бажаний формат виводу (location, issue, severity, suggested fix)","Ще детальніша прозова специфікація формату","Просити модель саму вигадати формат щоразу","Збільшити кількість проходів рев'ю"],a:0,ex:"Few-shot приклади — найдієвіший спосіб домогтися консистентного, actionable формату (location/issue/severity/fix), коли самих інструкцій недостатньо. Більше прози (B) чи свобода формату (C) не дають стабільності; більше проходів (D) не про формат."},
  {id:"S5Q10",s:5,d:3,q:"Авто-генерація тестів у CI пропонує тести, що дублюють уже наявні сценарії. Як це зменшити?",opts:["Передавати наявні тестові файли в контекст, щоб генерація уникала дублювання вже покритих сценаріїв","Збільшити кількість згенерованих тестів, щоб «перекрити» дублі","Вимкнути авто-генерацію тестів узагалі","Генерувати тести випадково й видаляти схожі постфактум"],a:0,ex:"Щоб уникнути дублів, наявні тестові файли подають у контекст — генерація бачить, що вже покрито. Більше тестів (B) множить дублі; вимкнення (C) втрачає користь; випадкова генерація з пост-чисткою (D) неефективна."},
  {id:"S5Q11",s:5,d:3,q:"Якість і цінність авто-генерованих тестів у CI низька — багато low-value тестів. Який механізм найкраще передає Claude Code потрібний контекст у CI?",opts:["Документувати у CLAUDE.md стандарти тестування, критерії цінних тестів і доступні fixtures","Класти всі інструкції в один довгий рядок CLI-команди щоразу","Покладатися на дефолтну поведінку моделі без жодного контексту","Зберігати стандарти лише у вікі команди поза репозиторієм"],a:0,ex:"CLAUDE.md — механізм передати CI-інстансу Claude Code контекст проєкту (стандарти тестування, критерії цінних тестів, fixtures), що підвищує якість і ріже low-value вивід. Довгий CLI-рядок (B) некерований; дефолти без контексту (C) і зовнішня вікі (D) до моделі не доходять."},
  {id:"S5Q12",s:5,d:4,q:"Ви ганяєте документи через Batches API (обробка до 24 год) і маєте дотриматись SLA 30 годин. Як спланувати подачу батчів?",opts:["Подавати батчі у вікнах ~4 години, щоб гарантувати 30-годинний SLA з урахуванням до 24 год обробки","Подати все одним батчем раз на добу й сподіватись, що встигне","Перейти на синхронний API, бо batch не підходить для жодних SLA","Подавати по одному документу окремими батчами щохвилини"],a:0,ex:"Частоту подачі рахують від SLA-обмежень: при обробці до 24 год і цілі 30 год вікна подачі ~4 год гарантують дотримання. Один батч на добу (B) ризикує не вкластися; повна відмова від batch (C) втрачає економію; по одному документу (D) неефективно."},
  {id:"S5Q13",s:5,d:4,q:"Одна категорія перевірок дає стільки false positives, що розробники втрачають довіру навіть до точних категорій. Який прагматичний крок?",opts:["Тимчасово вимкнути високо-FP категорію, щоб відновити довіру, паралельно покращуючи промпт для неї","Лишити все як є — довіра відновиться сама","Знизити загальну кількість усіх знахідок наполовину","Видалити всі категорії, крім стилю"],a:0,ex:"Високий рівень FP у категорії підриває довіру й до точних категорій. Прагматично — тимчасово вимкнути проблемну категорію, відновити довіру й паралельно доопрацьовувати промпт. Бездіяльність (B), сліпе скорочення (C) чи лишання лише стилю (D) не розв'язують проблему адресно."},
  {id:"S5Q14",s:5,d:4,q:"Воркфлоу потребує, щоб у межах одного запиту модель викликала інструмент, отримала результат і продовжила міркувати (multi-turn tool calling). Чи годиться для цього Batches API?",opts:["Ні — Batches API не підтримує multi-turn tool calling у межах одного запиту; для такого воркфлоу потрібен синхронний API","Так — batch підтримує повний multi-turn tool calling, треба лише polling","Так, якщо додати custom_id до кожного ходу","Так, але лише з прапорцем --interactive"],a:0,ex:"Batch API не підтримує multi-turn tool calling у межах одного запиту (не можна виконати інструмент посеред запиту й повернути результат). Для такого потрібен синхронний API. custom_id (C) лише корелює пари запит/відповідь, а не вмикає multi-turn."},
  {id:"S5Q15",s:5,d:3,q:"Чому в CI-рев'ю варто використовувати окремий інстанс Claude, а не ту саму сесію, що згенерувала код?",opts:["Та сама сесія зберігає reasoning-контекст генерації й гірше критикує власні зміни; незалежний інстанс рев'ю об'єктивніший","Бо одна сесія не може фізично запустити інструмент Read двічі","Бо інстанси завжди використовують різні моделі","Бо це єдиний спосіб увімкнути --output-format json"],a:0,ex:"Session context isolation: сесія, що згенерувала код, менш ефективна в рев'ю власних змін через збережений reasoning-контекст; незалежний інстанс рев'ю об'єктивніший. Інші пояснення (B, C, D) — технічно хибні."},
  {id:"S5Q16",s:5,d:4,q:"Колега боїться, що few-shot приклади змусять модель ловити лише ті патерни, що в прикладах, і пропускати нові. Що насправді?",opts:["Few-shot приклади дозволяють моделі узагальнювати судження на нові патерни, а не лише матчити наперед задані кейси","Так і є — few-shot завжди обмежує модель лише прикладами","Few-shot працює тільки для форматування, але не для суджень","Few-shot варто давати лише по одному прикладу, інакше шкідливо"],a:0,ex:"Few-shot приклади допомагають моделі генералізувати на нові патерни (а також демонструють обробку ambiguous-кейсів і формат), а не лише матчити задані. Тож побоювання необґрунтоване; твердження B, C, D невірні."},
  // SCENARIO 6
  {id:"S6Q1",s:6,d:4,q:"Ваша система екстракції інколи повертає синтаксично невалідний JSON, що ламає downstream. Який підхід найнадійніше гарантує schema-compliant вивід без JSON-синтаксичних помилок?",opts:["Tool use (tool_use) з JSON-схемою як вхідними параметрами інструмента, з якого витягують структуровані дані","Просити модель «повертати валідний JSON» у system prompt і парсити відповідь","Регулярками лагодити невалідний JSON постфактум","Знизити temperature до нуля, щоб JSON завжди був валідним"],a:0,ex:"tool_use із JSON-схемою — найнадійніший спосіб гарантованого schema-compliant виводу, що усуває синтаксичні помилки JSON. Прохання в промпті (B) ймовірнісне; полагодження регулярками (C) крихке; temperature (D) не гарантує валідності схеми."},
  {id:"S6Q2",s:6,d:4,q:"Деякі вихідні документи не містять певних полів, а модель вигадує значення, щоб задовольнити required-поля схеми. Як це усунути?",opts:["Зробити такі поля optional/nullable, щоб модель повертала null замість фабрикації, коли інформації немає","Лишити поля required, але просити модель «не вигадувати»","Видалити ці поля зі схеми взагалі","Підвищити max_tokens, щоб модель знайшла відсутні значення"],a:0,ex:"Поля, яких може не бути в джерелі, проєктують optional/nullable — це не змушує модель фабрикувати значення під required. Прохання «не вигадувати» (B) ймовірнісне; видалення полів (C) втрачає дані там, де вони є; max_tokens (D) не створить відсутню інформацію."},
  {id:"S6Q3",s:6,d:4,q:"Валідація екстракції зафейлила (Pydantic/JSON-схема). Як побудувати retry, щоб модель виправилась?",opts:["Надіслати follow-up запит, що включає оригінальний документ, провалену екстракцію й конкретні помилки валідації для самокорекції","Просто повторити той самий запит ще раз без змін","Підвищити temperature й сподіватись на іншу відповідь","Відкинути документ як необроблюваний"],a:0,ex:"Retry-with-error-feedback: у follow-up додають документ, провалену екстракцію й конкретні помилки валідації — це скеровує модель до виправлення. Сліпий повтор (B) і temperature (C) не дають напрямку; відкидання (D) передчасне для виправних помилок."},
  {id:"S6Q4",s:6,d:4,q:"Валідація вимагає поле, якого в наданому документі просто немає (потрібна інформація існує лише в зовнішньому документі, що не передавався). Чи допоможе retry?",opts:["Ні — retry неефективний, коли потрібної інформації немає в джерелі; це не format/structural помилка, яку можна виправити повтором","Так — достатньо повторити кілька разів, і модель знайде значення","Так, якщо додати «дуже постарайся» в промпт","Так, якщо підвищити max_tokens"],a:0,ex:"Retry дієвий для format/structural помилок, але безсилий, коли інформації просто немає в наданому джерелі. Повтори (B), заклики (C) чи max_tokens (D) не створять відсутні дані — потрібен інший документ або позначення поля як відсутнього."},
  {id:"S6Q5",s:6,d:4,q:"Тип вхідного документа наперед невідомий, і у вас є кілька схем екстракції під різні типи. Як гарантувати, що модель таки викличе якусь extraction-схему, а не поверне текст?",opts:["Виставити tool_choice: \"any\", щоб модель була зобов'язана викликати один з extraction-інструментів","tool_choice: \"auto\", щоб модель сама вирішила, чи потрібен інструмент","Форсувати один конкретний інструмент через {\"type\":\"tool\",\"name\":\"...\"}","Прибрати схеми й покластися на вільний текст"],a:0,ex:"Коли тип документа невідомий, а схем кілька, tool_choice: \"any\" гарантує виклик якогось extraction-інструмента (модель сама обере відповідний). \"auto\" (B) дозволяє текст; форсування конкретного (C) недоречне за невідомого типу; вільний текст (D) — протилежне меті."},
  {id:"S6Q6",s:6,d:4,q:"Вам треба, щоб у пайплайні спершу гарантовано відпрацював саме extract_metadata, а вже потім — кроки збагачення. Як це забезпечити?",opts:["Форсувати конкретний інструмент через tool_choice: {\"type\":\"tool\",\"name\":\"extract_metadata\"}, а наступні кроки обробляти в подальших ходах","tool_choice: \"any\" і сподіватись, що метадані оброблять першими","tool_choice: \"auto\" з інструкцією в промпті","Запустити всі інструменти одночасно й відсортувати результат"],a:0,ex:"Щоб гарантувати, що конкретний інструмент викликається першим, форсують tool_choice на нього (extract_metadata), а решту обробляють у follow-up ходах. \"any\" (B) не фіксує саме цей інструмент; \"auto\" (C) ймовірнісне; одночасний запуск (D) не дає гарантованого порядку."},
  {id:"S6Q7",s:6,d:4,q:"Категорії в документах не фіксовані наперед — трапляються нові, плюс бувають неоднозначні випадки. Як спроєктувати поле категорії в схемі?",opts:["Enum зі значенням \"other\" + окреме detail-поле для розширюваності, і \"unclear\" для неоднозначних випадків","Жорсткий enum лише з відомих наперед значень без запасних","Вільний текстовий рядок без жодного enum","Required-число, що кодує категорію"],a:0,ex:"Для розширюваних категорій додають enum + \"other\" з detail-рядком, а для неоднозначних — значення \"unclear\". Жорсткий enum (B) не вмістить нові категорії; вільний текст (C) втрачає структуру; числовий код (D) непрозорий і крихкий."},
  {id:"S6Q8",s:6,d:4,q:"Навіть з tool_use і строгою схемою екстракції з інвойсів інколи line items не сумуються до total, або значення опиняється в неправильному полі. Що це за тип помилок і як їх ловити?",opts:["Це семантичні помилки (tool_use усуває лише синтаксичні); ловити їх через self-correction: витягувати calculated_total поряд зі stated_total і флагати розбіжності","Це синтаксичні помилки, які tool_use уже повністю усуває","Достатньо знизити temperature до нуля","Достатньо додати ще одне required-поле total"],a:0,ex:"Строгі схеми через tool_use усувають синтаксичні, але не семантичні помилки (суми не сходяться, значення в чужому полі). Їх ловлять валідацією: extract calculated_total vs stated_total і флагати розбіжності. B хибне; temperature (C) і ще одне поле (D) суті не міняють."},
  {id:"S6Q9",s:6,d:5,q:"Ваша система звітує 97% загальної точності екстракції. Чому покладатись лише на цю агрегатну метрику ризиковано перед автоматизацією?",opts:["Агрегатна точність може маскувати погану продуктивність на конкретних типах документів чи полях; треба аналізувати точність по типу документа й по полю окремо","97% — достатньо, додатковий аналіз зайвий","Треба лише підняти поріг до 99% загалом","Достатньо збільшити вибірку, не розбиваючи її на сегменти"],a:0,ex:"Агрегатні метрики (напр. 97%) можуть приховувати слабку якість на окремих типах документів/полях. Перед автоматизацією точність валідують по типу документа й по полю. Сама по собі вища планка (C) чи більша нерозбита вибірка (D) проблему сегментів не виявлять."},
  {id:"S6Q10",s:6,d:5,q:"Ви хочете вимірювати реальний рівень помилок саме серед high-confidence екстракцій і ловити нові патерни помилок. Який метод найкращий?",opts:["Stratified random sampling high-confidence екстракцій для постійного виміру error rate і виявлення нових патернів","Перевіряти вручну лише ті екстракції, де модель сама позначила низьку впевненість","Перевіряти випадкові 1% усіх екстракцій без стратифікації","Покладатись на самозвітований confidence без жодних перевірок"],a:0,ex:"Stratified random sampling саме high-confidence екстракцій вимірює там error rate і виявляє нові патерни помилок, які інакше лишились би непоміченими. Перевірка лише low-confidence (B) пропускає приховані помилки у «впевнених»; нестратифікований семпл (C) і довіра до confidence (D) менш надійні."},
  {id:"S6Q11",s:6,d:5,q:"У вас обмежена reviewer-потужність. Які екстракції варто маршрутизувати на людський перегляд у першу чергу?",opts:["Екстракції з низькою впевненістю моделі або з неоднозначних/суперечливих джерел — пріоритезуючи обмежену потужність рев'юерів","Випадкову частину всіх екстракцій незалежно від впевненості","Лише ті, де впевненість найвища, бо вони найважливіші","Жодні — повністю довіряти моделі"],a:0,ex:"На людський перегляд маршрутизують екстракції з низькою впевненістю або з неоднозначних/суперечливих джерел, концентруючи обмежену потужність рев'юерів там, де ризик найбільший. Решта варіантів або марнують ресурс, або лишають ризиковані кейси без перевірки."},
  {id:"S6Q12",s:6,d:4,q:"Required-поля інколи виходять порожніми/null, бо документи мають дуже різну структуру (inline-цитати vs бібліографії, наративні описи vs структуровані таблиці). Що найкраще покращить обробку цієї варіативності?",opts:["Few-shot приклади, що демонструють коректну екстракцію з документів різної структури","Зробити всі поля required й заборонити null","Прибрати валідацію, щоб порожні поля не блокували","Збільшити temperature для «креативнішого» пошуку даних"],a:0,ex:"Few-shot приклади різних структур документів (inline-цитати vs бібліографії, наратив vs таблиці) покращують обробку варіативності й зменшують порожні поля. Жорсткі required (B) спровокують фабрикацію; зняття валідації (C) ховає проблему; temperature (D) не про структуру."},
  {id:"S6Q13",s:6,d:4,q:"Ви подали батч зі 100 документів через Batches API; частина зафейлила, зокрема через перевищення контекстного ліміту. Як обробити збої?",opts:["Перездати лише провалені документи (за custom_id) з відповідними модифікаціями, напр. чанкуванням тих, що перевищили контекст","Перездати весь батч зі 100 документів з нуля","Відкинути всі провалені документи без обробки","Перевести весь процес на синхронний API назавжди"],a:0,ex:"Збої батчу обробляють адресно: перездають лише провалені (ідентифіковані за custom_id) з потрібними модифікаціями (чанкування завеликих документів). Перездача всього (B) марнотратна; відкидання (C) втрачає дані; повна відмова від batch (D) надмірна реакція."},
  {id:"S6Q14",s:6,d:5,q:"Ви хочете, щоб пороги перегляду базувались на надійних confidence-оцінках. Як отримати калібровані field-level confidence?",opts:["Просити модель видавати field-level confidence, а пороги калібрувати на labeled validation set","Брати самозвітований confidence моделі як є, без калібрування","Виставити єдиний фіксований поріг 0.5 для всіх полів","Відмовитись від confidence і перевіряти все вручну"],a:0,ex:"Field-level confidence калібрують за допомогою labeled validation set, і вже за ним налаштовують пороги маршрутизації на рев'ю. Сирий самозвіт (B) погано калібрований; універсальний 0.5 (C) ігнорує відмінності полів; ручна перевірка всього (D) не масштабується."},
  {id:"S6Q15",s:6,d:4,q:"Джерела мають непослідовне форматування (дати, одиниці виміру, неформальні позначення), хоча сама вихідна схема строга. Як це найкраще врахувати?",opts:["Включити правила нормалізації форматів прямо в промпт поряд зі строгою output-схемою","Послабити схему до вільного тексту, щоб вмістити будь-який формат","Ігнорувати документи з нестандартним форматуванням","Покластися на те, що строга схема сама нормалізує формати"],a:0,ex:"Непослідовне форматування джерел адресують, додаючи правила нормалізації в промпт поряд зі строгою схемою виводу. Послаблення схеми (B) втрачає гарантії; ігнорування документів (C) втрачає дані; строга схема сама форматів не нормалізує (D)."},
  {id:"S6Q16",s:6,d:4,q:"У джерелах інколи трапляються внутрішньо суперечливі дані (напр. дві різні суми для одного значення). Як спроєктувати схему, щоб це не губилось мовчки?",opts:["Додати boolean conflict_detected (та за потреби обидва значення), щоб явно сигналізувати про суперечність у джерелі","Просто брати перше зустрінуте значення й не позначати конфлікт","Усереднювати суперечливі значення в одне поле","Відкидати весь документ при будь-якій суперечності"],a:0,ex:"Внутрішні суперечності джерела роблять явними через прапорець conflict_detected (і збереження обох значень) — щоб downstream бачив проблему. Мовчазний вибір першого (B), усереднення (C) чи відкидання документа (D) приховують або втрачають інформацію."},

  // ===================== SCENARIO 1 — додаткові =====================
  {id:"S1Q17",s:1,d:4,q:"Агент має класифікувати запит клієнта на категорії (RETURN/EXCHANGE/COMPLAINT/BILLING) для автоматичної маршрутизації. System prompt каже «відповідай лише назвою категорії», але агент інколи пише «Здається, це RETURN». Що гарантує коректний формат?",opts:["tool_use зі схемою, де requestType — enum з допустимих значень: модель зобов'язана обрати одне","Підсилити system prompt: «відповідай ТІЛЬКИ одним словом — назвою категорії»","Парсити текстову відповідь регулярками, витягуючи першу відому категорію","Знизити temperature до нуля для детермінованого виводу"],a:0,ex:"tool_use з enum-схемою — єдиний спосіб структурно гарантувати вивід одного з допустимих значень. Prompt-інструкція (B) знижує частоту відхилень, але не усуває їх — ймовірнісна; regex (C) крихкий до формулювань; temperature (D) не обмежує словниковий запас моделі."},
  {id:"S1Q18",s:1,d:1,q:"escalate_to_human повертає помилку «no agents available». Агент має повторити спробу через 30 секунд, але зараз просто завершує діалог без вирішення. Яке архітектурне рішення правильне?",opts:["PostToolUse hook, що перехоплює помилку ескалації, ставить запит у чергу з delay і планує retry","Додати в system prompt: «якщо ескалація не вдалась — зачекай хвилину і спробуй ще раз»","Збільшити timeout escalate_to_human, щоб інструмент чекав на доступного оператора","Якщо ескалація не вдалась — вирішувати питання самостійно без оператора"],a:0,ex:"PostToolUse hook дає детерміновану логіку retry з чергою і затримкою — не залежить від поведінки моделі. Prompt-інструкція (B) ймовірнісна й не може реалізувати реальну затримку в runtime; збільшення timeout (C) — для latency, не для availability; самостійне вирішення (D) суперечить вимозі ескалації."},
  {id:"S1Q19",s:1,d:5,q:"Довга сесія підтримки накопичила 8 tool-викликів, кожен повертає 20+ полів JSON. Контекст наближається до ліміту. Як діяти до переповнення?",opts:["Підсумувати завершені підзадачі та оброблені tool-результати, зберігши лише активний стан кейсу і pending-пункти","Збільшити розмір контекстного вікна через параметри моделі","Видаляти найстаріші повідомлення незалежно від вмісту","Починати нову сесію і просити клієнта повторити питання"],a:0,ex:"Вибіркове стиснення — конденсувати завершені підзадачі й verbose tool-виводи, зберігаючи активний стан — підтримує безперервність без переповнення. Збільшення вікна (B) — обхід, не рішення патерну накопичення. Видалення найстаріших (C) може знищити критичні ранні дані клієнта. Рестарт (D) руйнує UX."},
  {id:"S1Q20",s:1,d:2,q:"lookup_order приймає orderId АБО email АБО customerId, але агент часто передає всі три поля одночасно навіть маючи лише один — це викликає помилки валідації. Найімовірніша причина?",opts:["Опис інструмента не пояснює OR-відношення між полями — агент вважає, що всі три обов'язкові","Баг у валідації бекенду — треба приймати будь-яку комбінацію полів","Агент неправильно парсить JSON-відповідь попереднього інструмента","Низька temperature змушує модель «обережно» заповнювати всі поля"],a:0,ex:"Опис інструмента — основний механізм, за яким модель розуміє контракт. Нечітке OR-відношення (відсутність anyOf у схемі, немає прикладів) змушує модель заповнювати всі поля «на всяк випадок». Виправлення опису і anyOf у JSON-схемі — перший крок. Інші варіанти не стосуються причини."},

  // ===================== SCENARIO 2 — офіційне Q6 з PDF + доповнення =====================
  // Це офіційне sample question 6 з Exam Guide (Task 3.3: path-specific rules)
  {id:"S2Q21",s:2,d:3,q:"Ваш кодбейс має різні конвенції: React-компоненти — functional style, API-handlers — async/await з конкретним error handling. Тест-файли розкидані по всьому проєкту поруч із кодом (напр. Button.test.tsx поруч з Button.tsx). Ви хочете, щоб Claude автоматично застосовував правильні конвенції при генерації — незалежно від місця файлу. Найбільш підтримуваний підхід?",opts:["Створити файли правил у .claude/rules/ з YAML frontmatter з glob-патернами для умовного завантаження конвенцій по шляху файлу","Зібрати всі конвенції в кореневому CLAUDE.md під заголовками і покластися на Claude самостійно визначати релевантну секцію","Створити skills у .claude/skills/ для кожного типу коду з конвенціями у SKILL.md","Покласти окремий CLAUDE.md у кожну піддиректорію з конвенціями для тої зони"],a:0,ex:".claude/rules/ з glob-патернами (напр. **/*.test.tsx) дозволяє автоматично застосовувати конвенції за шляхом файлу незалежно від директорії — ідеально для тест-файлів по всьому проєкту. Консолідація в CLAUDE.md (B) покладається на інференцію, а не точне зіставлення. Skills (C) потребують ручного виклику. Окремі CLAUDE.md по директоріях (D) не вирішують проблему файлів, розкиданих по кодбейсу."},
  {id:"S2Q17",s:2,d:4,q:"Команда хоче, щоб Claude Code генерував тести у специфічному стилі (describe/it блоки, конкретні assertion-бібліотеки, стиль коментарів). Опис у CLAUDE.md не дає стабільного результату. Що найефективніше?",opts:["Додати у CLAUDE.md 2–3 конкретні приклади тестів у бажаному стилі як few-shot","Детальніше описати стиль прозою: «використовуй describe/it, prefer expect().toBe()»","Підвищити temperature для більшої варіативності і відбирати кращий результат","Завжди давати завдання генерації тестів в окремій сесії без контексту"],a:0,ex:"Few-shot приклади є найефективнішим способом закріпити конкретний стиль — модель узагальнює патерн, а не слідує прозовому опису. Детальніша проза (B) допомагає, але не так надійно; підвищення temperature (C) додає варіативність, а не консистентність; окрема сесія (D) ігнорує проблему."},
  {id:"S2Q18",s:2,d:5,q:"Під час рефакторингу 30+ файлів контекст сесії заповнюється і Claude починає «забувати» зміни, внесені на початку — посилається на старі назви функцій. Яка стратегія найефективніша?",opts:["Вести structured changelog-файл у репозиторії: після кожного файлу записувати що змінено — Claude читає його як джерело правди","Перезапускати сесію після кожних 5 файлів","Збільшити max_tokens для довших відповідей","Просити Claude «запам'ятати» зроблені зміни через system prompt"],a:0,ex:"Structured changelog (зовнішній persistent файл) дозволяє агенту читати актуальний стан змін незалежно від контекстного вікна. Перезапуск сесій (B) щоразу втрачає прогрес; max_tokens (C) стосується виводу, не вікна; «запам'ятати» в system prompt (D) зміни зникнуть при переповненні."},
  {id:"S2Q19",s:2,d:1,q:"Задача потребує змін у 15 взаємопов'язаних файлах: API, адаптери, тести, документація. Яка стратегія декомпозиції оптимальна?",opts:["Prompt chaining: спершу план і граф залежностей, потім покрокові зміни у визначеному порядку з verification-чекпоінтами","Паралельний запуск 15 незалежних агентів — по одному на файл","Один великий промпт із повним описом усіх 15 змін одночасно","Починати зміни в довільному порядку й виправляти конфлікти по факту"],a:0,ex:"Взаємопов'язані зміни через кілька файлів вимагають координованого підходу: граф залежностей → зміни у правильному порядку → перевірка. Паралельні агенти (B) без координації створять конфлікти; один гігантський промпт (C) спричинить attention dilution; довільний порядок (D) порушить залежності."},
  {id:"S2Q20",s:2,d:3,q:"Команда хоче, щоб Claude Code автоматично дотримувався naming conventions, структури директорій і правил імпортів у всіх сесіях. Де і як налаштувати?",opts:["Project-level CLAUDE.md з конкретними прикладами conventions — автоматично завантажується у кожній сесії, версіонується в git","Повторювати conventions у кожному промпті вручну","Зберігати правила у .eslintrc і розраховувати, що Claude їх прочитає автоматично","Налаштовувати conventions у ~/.claude/CLAUDE.md для усіх проєктів"],a:0,ex:"Project-level CLAUDE.md — правильне місце для командних conventions: версіонується разом з кодом, автоматично завантажується. Мануальне повторення (B) ненадійне і дорого за токенами; .eslintrc (C) Claude не читає автоматично без явного запиту; user-level ~/.claude (D) не шериться через VCS."},

  // Task 1.4: structured handoff при ескалації
  {id:"S1Q21",s:1,d:1,q:"Агент ескалує складний кейс до людського оператора, але той не має доступу до попередньої переписки. Яку інформацію зобов'язаний підготувати агент при ескалації?",opts:["Структурований handoff: ID клієнта, корінна причина, спробовані дії, рекомендована наступна дія — щоб оператор міг діяти без перечитування всього чату","Передати лише посилання на тікет, оператор сам знайде потрібне в системі","Повний текст діалогу скопіювати в поле коментаря","Нічого — оператор сам запитає клієнта про проблему"],a:0,ex:"Structured handoff summary — ID клієнта, причина, що намагались зробити, рекомендована дія — дозволяє оператору відразу продуктивно діяти без повторного аналізу довгого діалогу. Посилання на тікет (B) не гарантує, що оператор матиме контекст; повний текст (C) потребує зайвого читання; відсутня передача (D) перекладає тягар на клієнта."},

  // ===================== SCENARIO 3 — додаткові =====================
  {id:"S3Q17",s:3,d:4,q:"Synthesis-агент повертає фінальний звіт у вільному форматі — щоразу різна структура, різні назви секцій. Downstream-системи не можуть надійно парсити вивід. Як виправити?",opts:["Визначити JSON-схему звіту і виставити її як tool_use — synthesis зобов'язаний заповнити всі поля у визначеній структурі","Додати в промпт synthesis-агента деталізований шаблон структури звіту","Парсити вивід synthesis-агента NLP-постпроцесингом на бекенді","Просити synthesis-агента закінчувати звіт JSON-блоком після основного тексту"],a:0,ex:"tool_use з JSON-схемою дає структурно гарантований вивід — synthesis зобов'язаний заповнити визначені поля. Шаблон у промпті (B) знижує варіативність, але не гарантує схему. NLP-постпроцесинг (C) — крихка обробка вільного тексту. JSON-блок у кінці (D) все одно вільний текст, що вимагає парсингу."},
  {id:"S3Q18",s:3,d:2,q:"web-search субагент має єдиний інструмент search(query), що повертає сирий HTML. Synthesis-агент витрачає багато токенів на парсинг. Як покращити дизайн інструментів?",opts:["Розбити на purpose-specific інструменти: search_web (структуровані результати), fetch_page (clean text), extract_facts (ключові факти з джерела)","Дати synthesis-агенту прямий доступ до search(query) для самостійного пошуку","Збільшити max_tokens synthesis-агента для обробки сирого HTML","Кешувати HTML-відповіді і парсити їх окремим сервісом до передачі"],a:0,ex:"Purpose-specific інструменти з чіткими output-контрактами (структуровані результати, clean text, key facts) усувають парсинг downstream. Прямий доступ synthesis-агента (B) порушує separation of concerns; збільшення max_tokens (C) не вирішує токен-проблему; кеш-сервіс (D) правильний патерн, але питання про дизайн інструментів."},
  {id:"S3Q19",s:3,d:1,q:"Деякі research-запити прості (один аспект, одне джерело), але coordinator завжди запускає повний пайплайн усіх субагентів. Як проєктувати coordinator для адаптивності?",opts:["Coordinator першим кроком аналізує складність запиту і динамічно обирає мінімально необхідний набір субагентів","Зробити всіх субагентів швидшими, щоб повний пайплайн не був проблемою","Замінити coordinator лінійним ланцюгом і запускати всі кроки послідовно","Додати word-threshold: короткі запити йдуть лише до web-search"],a:0,ex:"Адаптивна декомпозиція на основі аналізу складності — правильний патерн: різні запити потребують різних субагентів. Прискорення всіх (B) не вирішує марнування для простих запитів; лінійний ланцюг (C) не дозволяє пропускати кроки; word-threshold (D) надто груба евристика."},
  {id:"S3Q20",s:3,d:5,q:"Coordinator запускає research-сесії щоденно. Нові запити часто перекривають вже досліджені теми, але кожна сесія починається з нуля. Як накопичувати знання між сесіями?",opts:["Persistent knowledge store (файл або БД) зі структурованими знахідками і датами — coordinator читає його на початку і передає релевантний контекст субагентам","Зберігати повні логи кожної сесії і передавати їх у контекст наступної","Збільшити частоту запусків, щоб менше перекривання","Просити користувача вказувати вже досліджені теми перед кожним запуском"],a:0,ex:"Persistent knowledge store зі структурованими знахідками (не сирими логами) дозволяє ефективно інтегрувати минулі дослідження без переповнення контексту. Повні логи (B) занадто об'ємні і переповнять вікно; частіші запуски (C) не вирішують проблему; ручне вказування (D) перекладає роботу на людину."},

  // Task 4.4: retry limits — коли retry не допоможе
  {id:"S3Q21",s:3,d:4,q:"Synthesis-агент витягує metadata з документа, але поле «рік публікації» стабільно повертає помилку валідації — поле обов'язкове в схемі, але в усіх вхідних документах ця інформація відсутня. Чи допоможе retry?",opts:["Ні — retry вирішує format/structural помилки, але безсилий, коли інформація відсутня в джерелі; поле треба зробити nullable","Так — при достатній кількості спроб модель «знайде» значення в тексті","Так, якщо передати детальніше пояснення помилки у follow-up","Так, якщо збільшити max_tokens для ретельнішого аналізу документа"],a:0,ex:"Retry ефективний для format/structural помилок (неправильний тип, неправильне форматування), але якщо інформація фізично відсутня в документі — ніяка кількість спроб не допоможе. Правильне рішення: зробити поле nullable, щоб модель повертала null замість фабрикації. Варіанти B, C, D неправильно припускають, що retry може створити відсутні дані."},

  // ===================== SCENARIO 4 — додаткові =====================
  {id:"S4Q17",s:4,d:3,q:"Інженер хоче зрозуміти, як legacy authentication модуль взаємодіє з 12 залежними сервісами. Яка послідовність built-in інструментів найефективніша?",opts:["Grep → точки входу auth; Read → ключові файли; Glob → всі файли що імпортують auth; Read → трасування залежностей","Read усіх 12 файлів сервісів повністю наперед для повної картини","Bash → запустити grep -r вручну і передати вивід Claude для аналізу","Glob → список всіх файлів проєкту; Read → кожен файл по черзі"],a:0,ex:"Інкрементальний підхід (Grep для точок входу → Read ключових файлів → Glob для залежностей → Read для трасування) ефективно використовує контекст. Read всіх файлів наперед (B) з'їдає контекст без цілеспрямованості; Bash-grep (C) дублює вбудований Grep; Glob всіх + Read по черзі (D) переповнить контекст."},
  {id:"S4Q18",s:4,d:4,q:"Claude генерує технічну документацію для функцій, але вона або надто коротка (парафраз сигнатури), або надто довга (пояснює очевидне). Як отримати стабільно корисну документацію?",opts:["Надати 2–3 приклади добре задокументованих функцій з того самого кодбейсу як few-shot","Просити Claude «бути стислим, але повним» у кожному промпті","Генерувати документацію двічі і вибирати кращу версію","Встановити точний ліміт слів у промпті (напр. «рівно 3 речення»)"],a:0,ex:"Few-shot приклади з того самого кодбейсу показують правильний рівень деталізації і стиль команди. «Бути стислим, але повним» (B) — неоднозначна інструкція; двічі генерувати (C) дорого і суб'єктивно; точний ліміт слів (D) обмежує, але не передає бажану якість."},
  {id:"S4Q19",s:4,d:5,q:"Після 2 годин дослідження кодбейсу Claude починає давати менш точні відповіді — посилається на «типові патерни» замість конкретних класів, знайдених раніше. Симптом і причина?",opts:["Деградація через переповнення контексту: ранні специфічні знахідки витісняються новим вмістом — модель узагальнює замість конкретики","Модель «втомлюється» від тривалих сесій і потребує перезапуску","Кодбейс занадто великий для будь-якої AI-моделі","Проблема у використанні Read замість Grep для пошуку"],a:0,ex:"У довгих сесіях ранні знахідки витісняються і модель «зісковзує» на узагальнення. Рішення: scratchpad-файл із ключовими знахідками, на який посилаються в наступних питаннях. Моделі не «втомлюються» (B); проблема не в розмірі кодбейсу (C); вибір Grep vs Read (D) не стосується причини."},
  {id:"S4Q20",s:4,d:1,q:"Ви розслідуєте performance-регресію з двома рівно-вірогідними гіпотезами: DB-запити або кешування. Обидві потребують окремого глибокого аналізу від спільного baseline. Що використати?",opts:["fork_session від спільного baseline-аналізу: одна гілка — DB, інша — кеш, незалежно і паралельно","--resume однієї сесії і перемикатись між гіпотезами по черзі","Дві повністю незалежні нові сесії без спільного контексту","Одна сесія, послідовно: спершу DB, потім кеш"],a:0,ex:"fork_session створює незалежні гілки від спільного baseline — ідеально для паралельного дослідження двох гіпотез без дублювання аналізу. --resume однієї сесії (B) змішає гілки; дві незалежні сесії (C) дублюють базовий аналіз; послідовно (D) вдвічі довше без переваг."},

  // Task 3.2: argument-hint frontmatter
  {id:"S4Q21",s:4,d:3,q:"Ваш skill для генерації boilerplate запускається командою /gen, але розробники забувають передати обов'язковий аргумент (назву компонента) і skill падає з помилкою. Який механізм Claude Code вирішує це?",opts:["argument-hint у frontmatter SKILL.md — Claude підказує розробнику ввести потрібний параметр при виклику skill без аргументів","Додати перевірку в тіло skill і виводити повідомлення про помилку","Зробити назву компонента necessary полем у системному промпті","Видалити можливість запуску skill без аргументів через allowed-tools"],a:0,ex:"argument-hint у frontmatter SKILL.md — стандартний механізм Claude Code для запиту обов'язкових параметрів при виклику skill без аргументів. Власна перевірка в тілі (B) працює, але дублює вбудований механізм; системний промпт (C) не допоможе при відсутньому аргументі; allowed-tools (D) — для обмеження інструментів, не для параметрів."},

  // ===================== SCENARIO 5 — додаткові =====================
  {id:"S5Q17",s:5,d:3,q:"CI-пайплайн запускає Claude Code для аналізу PR, але Claude не має доступу до корпоративних стандартів кодування. Claude Code повертає generic рекомендації замість специфічних для команди. Як виправити?",opts:["Зберігати стандарти кодування в CLAUDE.md репозиторію — автоматично завантажується у CI-сесію без додаткових аргументів","Передавати стандарти через довгий --system-prompt аргумент у кожному CI-виклику","Зберігати стандарти у зовнішній вікі і просити розробників передавати URL","Хардкодити стандарти у CI-скрипті через env var"],a:0,ex:"Project-level CLAUDE.md автоматично надає Claude Code контекст команди — версіонується в git разом з кодом, підхоплюється без змін у CI-скрипті. Довгий --system-prompt (B) некероване і дорого; зовнішня вікі (C) до моделі не доходить без явного читання; env var (D) обходить призначений механізм."},
  {id:"S5Q18",s:5,d:4,q:"CI code review флагає будь-яке використання innerHTML або eval() як проблему, навіть у перевірених утилітах. False positive rate критично підриває довіру команди. Як уточнити критерій?",opts:["Змінити критерій: «флагати innerHTML/eval лише коли вхідні дані надходять з зовнішнього джерела без санітизації» — конкретна умова замість загальної заборони","Повністю вимкнути перевірку innerHTML/eval","Додати «перевіряй лише критичні security-проблеми» і підняти поріг у цілому","Вручну вносити дозволені виклики у whitelist перед кожним рев'ю"],a:0,ex:"Конкретний категоріальний критерій (небезпека залежить від джерела даних) різко знижує false positives, зберігаючи захист від реальних вразливостей. Вимкнення перевірки (B) усуває і справжні проблеми; загальний поріг (C) знизить точність для інших категорій; whitelist (D) вимагає ручного обслуговування."},
  {id:"S5Q19",s:5,d:5,q:"PR зростав поступово: 6 комітів за 3 дні. Claude переглядає лише diff останнього коміту, але пропускає проблеми від взаємодії ранніх і пізніх змін. Як виправити?",opts:["Передавати повний PR diff (всі коміти від base branch) у контекст рев'ю, а не лише останній коміт","Запускати окреме рев'ю на кожен коміт і агрегувати результати","Збільшити max_tokens, щоб умістити більше коду в одному виклику","Просити Claude самостійно запитати попередні diff'и при потребі"],a:0,ex:"Крос-коміт проблеми виявляються тільки при аналізі повного PR diff — взаємодія ранніх і пізніх змін невидима з partial diff. Окремі рев'ю (B) теж не побачать взаємодію між комітами; max_tokens (C) стосується виводу; самостійний запит (D) Claude не може ініціювати без інструменту."},
  {id:"S5Q20",s:5,d:1,q:"Ви хочете паралельно виконати security review, performance review і correctness review великого PR. Яка архітектура найефективніша?",opts:["Три незалежні Claude-інстанси паралельно: кожен спеціалізується на одному вимірі зі своїм промптом і критеріями","Один промпт із проханням перевірити всі три виміри одночасно","Послідовно: security, потім performance, потім correctness в одній сесії","Один агент з трьома різними значеннями temperature для кожного виміру"],a:0,ex:"Паралельні спеціалізовані інстанси (по одному на вимір) дають швидкість і глибину кожного домену. Один промпт для всіх (B) спричиняє attention dilution; послідовно (C) — 3× повільніше без переваг якості; різні temperature (D) не змінюють здатність аналізувати різні виміри."},

  // Task 5.x: coverage gap reporting (Task 1.2 iterative refinement)
  {id:"S5Q21",s:5,d:1,q:"Після автоматичного code review Claude звітує про кілька проблем, але через постійні false positives в одній з категорій (стиль) розробники ігнорують весь вивід — навіть справжні баги. Що зробити в першу чергу?",opts:["Тимчасово вимкнути категорію з високим рівнем false positives і паралельно покращувати критерії для неї — це відновить довіру до точних категорій","Залишити все як є і додати в CLAUDE.md пояснення, що не всі знахідки критичні","Знизити загальну кількість знахідок наполовину, незалежно від категорії","Перейти з автоматичного рев'ю на виключно ручне"],a:0,ex:"Висока кількість false positives в одній категорії отруює довіру до всього рев'ю. Тимчасове вимкнення проблемної категорії відновлює корисність інших + дає час на якісне покращення критеріїв. Пояснення в CLAUDE.md (B) не усуває технічну проблему; сліпе скорочення (C) ріже і важливе; ручне рев'ю (D) скасовує автоматизацію."},

  // ===================== SCENARIO 6 — додаткові =====================
  {id:"S6Q17",s:6,d:4,q:"Документи мають ієрархічну структуру: invoice → line_items[] → adjustments[]. Поточна плоска схема втрачає ієрархію. Як правильно спроєктувати схему?",opts:["Вкладені об'єкти: Invoice містить масив LineItem, кожен LineItem — масив Adjustment — ієрархія відображена в JSON-структурі","Зберігати поля плоско з prefix-номерами (item1_price, item1_qty, item2_price)","Витягувати лише верхній рівень (invoice total), ігноруючи line items","Зберігати line items як JSON-рядок всередині рядкового поля"],a:0,ex:"Вкладені об'єкти точно відображають ієрархічну природу даних і дозволяють downstream-системам коректно обробляти довільну кількість елементів. Плоска схема з prefix (B) негнучка і ламається при змінній кількості items; ігнорування line items (C) втрачає дані; JSON-рядок у рядку (D) унеможливлює типізовану обробку."},
  {id:"S6Q18",s:6,d:5,q:"Система показує 95% точності на тестовому наборі, але клієнти скаржаться на помилки саме в рахунках від нових постачальників. Яка причина і рішення?",opts:["Тестовий набір не включає документи нових постачальників — потрібна стратифікована оцінка по типу документа і регулярне поповнення з продакшен-даними","95% — достатня точність, проблема в завищених очікуваннях клієнтів","Підняти поріг confidence для всіх екстракцій","Перейти на інший LLM із вищою загальною точністю"],a:0,ex:"Агрегатна метрика маскує погану продуктивність на нових форматах. Стратифікована оцінка (по постачальнику, формату, часовому вікну) і поповнення тестового набору продакшен-даними виявляє реальні слабкі місця. Ігнорування (B) не вирішить; підняття порогу (C) збільшить кількість відхилених, а не точність; зміна LLM (D) без розуміння причини — ризик."},
  {id:"S6Q19",s:6,d:1,q:"Великий батч документів потребує: (1) класифікації типу, (2) вибору схеми, (3) екстракції, (4) валідації. Яка архітектура оркестрації оптимальна?",opts:["Prompt chaining: кожен крок передає вивід наступному у визначеній послідовності; крок валідації запускає retry лише для невалідних","Один великий промпт, що виконує всі 4 кроки за один раз","4 незалежні агенти без координатора, кожен опрацьовує весь батч","Паралельний запуск усіх 4 кроків одночасно для кожного документа"],a:0,ex:"Prompt chaining — правильний патерн для передбачуваних послідовних кроків із явними залежностями. Вивід класифікації (крок 1) визначає схему (крок 2), тому паралелізм (D) між кроками неможливий. Один промпт для всіх 4 (B) спричиняє attention dilution. Незалежні агенти (C) не можуть передавати контекст між кроками."},
  {id:"S6Q20",s:6,d:2,q:"Система має два інструменти: extract_invoice і extract_contract. Обидва приймають raw_text. Агент часто викликає не той інструмент — invoice для контрактів і навпаки. Причина і рішення?",opts:["Описи інструментів не розрізняють типи документів: додати ключові ознаки кожного типу і приклади trigger-ситуацій в description","Об'єднати в один extract_document(type, raw_text) і дати агенту явно вказати тип","Форсувати tool_choice: auto — нехай модель вирішує сама","Додати preprocessing-крок, що класифікує документ перед передачею агенту"],a:0,ex:"Якість вибору інструмента пропорційна якості описів. Ознаки типу (invoice: line items, payment terms; contract: parties, obligations, duration) і приклади усувають неоднозначність вибору. Об'єднання (B) переносить проблему класифікації всередину агента; tool_choice: auto (C) — поточний стан, що не вирішує проблему; preprocessing (D) правильний патерн, але питання про описи."},
];

export function getQuestionsByDomain(domainId: number): Question[] {
  return QB.filter(q => q.d === domainId);
}

export function getQuestionsByScenario(scenId: number): Question[] {
  return QB.filter(q => q.s === scenId);
}

export const PASS_SCALED = 720;
export const TOTAL_EXAM_QUESTIONS = 60;
export const EXAM_DURATION_SEC = 120 * 60;
